import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, Check, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  BookOpen
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
