                                                {showAnswer && isCorrect ? <Check size={14} /> : showAnswer && isWrong ? <X size={14} /> : letter}
                                            </div>
                                            <div className="flex-1 text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
