                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-6 rounded-lg border-l-4 text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500 text-emerald-900' : 'bg-slate-100 border-slate-400 text-slate-800'}`}>
