                    >
                        <ChevronLeft size={16} /> Previous
                    </button>

                    <button 
                        onClick={() => {
                            if (currentQIndex === questions.length - 1) {
                                handleFinish();
                            } else {
                                setCurrentQIndex(prev => prev + 1);
                                setImgError(false);
                            }
                        }}
                        className="flex items-center gap-2 px-8 py-3 rounded-lg font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg hover:shadow-xl transition-all hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {currentQIndex === questions.length - 1 ? 'Submit Exam' : 'Next Question'} 
                        {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}
                    </button>
                </div>
            </main>

            {/* Sidebar (Question Palette) */}
            <aside className={`bg-white border-l border-slate-200 w-80 flex-col shrink-0 transition-transform duration-300 absolute lg:relative inset-y-0 right-0 z-40 lg:translate-x-0 shadow-2xl lg:shadow-none ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'} flex`}>
                <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                    <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400"><X size={20} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
                    <div className="grid grid-cols-5 gap-2">
                        {questions.map((q, i) => {
                            let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-400";
                            if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200";
                            else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-600";
                            else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";

                            return (
                                <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }}
                                    className={`aspect-square rounded flex items-center justify-center text-xs font-medium border transition-all relative group ${style}`}
                                >
                                    {i + 1}
                                    {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="p-5 border-t border-slate-200 bg-slate-50 space-y-3">
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-slate-800 rounded"></div> Current
                    </div>
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-slate-100 border border-slate-300 rounded"></div> Answered
                    </div>
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-amber-50 border border-amber-400 rounded"></div> Flagged
                    </div>
                    <button onClick={exitQuiz} className="w-full mt-4 py-3 border border-rose-200 text-rose-600 rounded-lg text-xs font-bold uppercase tracking-widest hover:bg-rose-50 transition-colors">
                        Abort Session
                    </button>
                </div>
            </aside>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Score Card) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
        <div className="h-full bg-slate-100 flex items-center justify-center p-4 overflow-y-auto custom-scrollbar">
            <div className="bg-white max-w-2xl w-full rounded-[1.5rem] shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500">
                <div className="bg-slate-900 p-8 text-center text-white relative overflow-hidden">
                    <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 to-slate-900"></div>
                    <div className="relative z-10">
                        <h2 className="text-3xl font-display font-bold mb-2">Examination Report</h2>
                        <p className="text-slate-400 uppercase tracking-widest text-xs font-bold">Session ID: OT-{Date.now().toString().slice(-6)}</p>
                    </div>
                </div>

                <div className="p-8 md:p-12 space-y-8 text-center">
                    <div className="flex justify-center items-center gap-8">
                        <div className="text-center">
                            <span className="block text-5xl font-black text-slate-900 mb-1">{percentage}%</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Final Grade</span>
                        </div>
                        <div className="w-px h-16 bg-slate-200"></div>
                        <div className="text-center">
                            <span className="block text-5xl font-black text-slate-900 mb-1">{score}</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Correct Answers</span>
                        </div>
                    </div>

                    <div className={`p-4 rounded-xl border-l-4 text-left ${percentage >= 70 ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                        <h4 className={`font-bold text-sm uppercase tracking-wider mb-1 ${percentage >= 70 ? 'text-emerald-800' : 'text-rose-800'}`}>
                            {percentage >= 70 ? 'Satisfactory Performance' : 'Academic Warning'}
                        </h4>
                        <p className="text-sm opacity-80">
                            {percentage >= 70 
                                ? "You have demonstrated competency in the selected modules. Maintain study habits." 
                                : "Performance falls below the departmental threshold. Recommend reviewing flagged topics in the Atlas."}
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {hasMistakes ? (
                            <button onClick={retryIncorrectOnly} className="py-4 rounded-xl border-2 border-rose-100 bg-rose-50 text-rose-700 font-bold uppercase text-xs tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retry Mistakes
                            </button>
                        ) : (
                            <button onClick={retrySession} className="py-4 rounded-xl border-2 border-slate-100 bg-slate-50 text-slate-700 font-bold uppercase text-xs tracking-widest hover:bg-slate-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retake Exam
                            </button>
                        )}
                        <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="py-4 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-bold uppercase text-xs tracking-widest hover:border-slate-400 transition-all flex items-center justify-center gap-2">
                            <FileText size={16} /> Audit Answers
                        </button>
                    </div>

                    <button 
                        onClick={() => saveAndExit(false)}
                        className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                    >
                        Conclude Session
                    </button>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW (Audit Mode) ---
  if (view === 'review') {
    return (
        <div className="h-full bg-slate-50 flex flex-col">
            <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                <h2 className="font-bold text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                    <FileText size={16} /> Audit Log
                </h2>
                <button onClick={() => setView('results')} className="text-xs font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900">
                    Return to Score
                </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 space-y-6">
                <div className="max-w-4xl mx-auto space-y-4">
                    {questions.map((q, i) => (
                        <div key={i} className={`bg-white rounded-xl border p-6 md:p-8 shadow-sm ${q.userAnswer === q.correctOption ? 'border-emerald-200' : 'border-rose-200'}`}>
                            <div className="flex gap-4">
                                <span className={`text-sm font-mono font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>Q{i+1}</span>
                                <div className="space-y-4 flex-1">
                                    <h3 className="font-medium text-slate-900 leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />

                                    {q.data.questionImage && (
                                        <div className="p-2 border border-slate-100 bg-slate-50 rounded-lg w-fit">
                                            <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 rounded" alt="ref" />
                                        </div>
                                    )}

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                                        <div className={`p-3 rounded-lg border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}>
                                            <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Your Selection</span>
                                            <span className="font-bold" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} />
                                        </div>
                                        {q.userAnswer !== q.correctOption && (
                                            <div className="p-3 rounded-lg border bg-slate-50 border-slate-200 text-slate-900">
                                                <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Correct Answer</span>
                                                <span className="font-bold" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

export default Quiz;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Sync with LocalStorage whenever mistakesVault changes
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the mistakes vault?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire mistakes history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    if (search.trim()) {
      const term = search.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, search, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategories, showMistakesOnly, showWrittenOnly]);

