                     <p className="text-sm font-medium text-emerald-800 leading-relaxed break-words" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-4 shrink-0">
                 <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest truncate max-w-[70%] text-left">{currentCard.category}</div>
