  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the mistakes vault?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire mistakes history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-6">
      {/* Search Header */}
      <div className={`rounded-[2.5rem] p-8 md:p-12 mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h2 className="text-3xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Mistakes" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Vault" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder={showMistakesOnly ? "Search known errors..." : "Search anatomy terms, chapters or definitions..."}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-14 pr-14 py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-white/50 outline-none focus:bg-white focus:text-slate-900 transition-all text-lg font-bold"
            />
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-slate-500 transition-colors" size={24} />
          </div>

          <div className="flex flex-wrap gap-3 items-center">
            {/* Filter Trigger Button */}
            <button 
              onClick={() => setIsFilterOpen(true)}
              className="flex items-center gap-2 px-6 py-3 bg-white text-slate-900 rounded-xl font-black uppercase text-xs tracking-widest shadow-lg hover:bg-slate-100 transition-all"
            >
              <Filter size={16} /> Filters
              {(selectedCategories.length > 0 || showMistakesOnly || showWrittenOnly) && (
                 <span className="bg-slate-900 text-white px-2 py-0.5 rounded-md">Active</span>
              )}
            </button>

            {showMistakesOnly && mistakesVault.length > 0 && (
                <button 
                    onClick={clearAllMistakes}
                    className="flex items-center gap-2 px-4 py-3 rounded-xl bg-black/20 text-white hover:bg-white hover:text-rose-600 transition-all text-[10px] font-black uppercase"
                >
                    <Trash2 size={14} /> Wipe Vault
                </button>
            )}

            <div className="flex-1"></div>
            <button 
                onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors text-white"
                title="Sort A-Z"
            >
                <ArrowUpDown size={18} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakesVault.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}
              <div className="p-8 flex-1">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200">{q.category}</span>
                  {mistakesVault.includes(q.id) && (
                    <div className="flex items-center gap-2">
                        <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Mistake</span>
                        <button 
                            onClick={(e) => removeMistake(q.id, e)}
                            className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                            title="Resolve this mistake"
                        >
                            <Trash2 size={12} /> Resolve
                        </button>
                    </div>
                  )}
                </div>
                <h3 className="text-xl font-black text-slate-800 leading-tight mb-4" dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, debouncedSearch) }} />
                <div className="relative pl-6 border-l-4 border-slate-200">
                  <p className="text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "No mistakes recorded. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-3 mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-14 px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Vault Filters"
      />
    </div>
  );
};

export default QuestionList;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Info, Search, Maximize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [search, setSearch] = useState('');

  // Performance: Pagination for grid
  const [visibleLimit, setVisibleLimit] = useState(24);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  // Mistakes Vault Logic
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Are you sure you want to permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Extract all unique diagrams
  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    // 1. Group questions by image
    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    // 2. Filter by Mistakes
    if (showMistakesOnly) {
        items = items.filter(item => item.hasMistake);
    }

    // 3. Filter by Category
    if (selectedCategories.length > 0) {
        items = items.filter(item => selectedCategories.includes(item.category));
    }

    // 4. Filter by Search
    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  // Reset pagination when filters change
  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);

  // PERFORMANCE: Only render visible items
  const visibleItems = atlasItems.slice(0, visibleLimit);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-white relative">
      {/* Atlas Header & Search */}
      <div className="p-4 md:p-6 border-b border-slate-100 bg-slate-50/50 flex gap-3 items-center">
        <div className="flex-1 relative group">
          <input 
            type="text" 
            placeholder={showMistakesOnly ? "Search mistakes gallery..." : "Filter atlas by system or structure..."} 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-12 pr-6 py-4 rounded-2xl bg-white border-2 border-slate-200 focus:border-rose-500 outline-none transition-all font-bold text-slate-700 shadow-sm"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-rose-500 transition-colors" size={20} />
        </div>

        <button 
             onClick={() => setIsFilterOpen(true)}
             className={`p-4 rounded-2xl border-2 transition-all flex items-center gap-2 shadow-sm ${selectedCategories.length > 0 || showMistakesOnly ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 bg-white text-slate-400 hover:border-slate-300'}`}
        >
             <Filter size={20} />
             {(selectedCategories.length > 0 || showMistakesOnly) && (
                 <span className="hidden md:inline text-[10px] font-black bg-rose-600 text-white px-2 py-0.5 rounded-md">
                    Filter Active
                 </span>
             )}
        </button>
      </div>

      {showMistakesOnly && (
          <div className="bg-amber-50 px-6 py-2 border-b border-amber-100 flex items-center justify-center gap-2">
              <AlertTriangle size={12} className="text-amber-600" />
              <span className="text-[10px] font-black text-amber-700 uppercase tracking-widest">Mistakes Gallery Mode</span>
          </div>
      )}

      <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar pb-32">
        {atlasItems.length > 0 ? (
            <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 content-visibility-auto">
            {visibleItems.map((item, idx) => (
                <div 
                key={idx} 
                onClick={() => setSelectedImage(item.url)}
                className={`group cursor-pointer bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all overflow-hidden flex flex-col ${item.hasMistake ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}
                >
                <div className="h-48 sm:h-56 bg-slate-50 flex items-center justify-center p-6 relative overflow-hidden">
                    <img src={cleanImageUrl(item.url)} className="max-w-full max-h-full object-contain transition-transform duration-500 group-hover:scale-110" alt="Diagram" loading="lazy" />
                    {item.hasMistake && (
                        <div className="absolute top-4 right-4 bg-amber-100 text-amber-600 p-2 rounded-full shadow-sm z-10">
                            <AlertTriangle size={16} />
                        </div>
                    )}
                    <div className="absolute inset-0 bg-rose-600/0 group-hover:bg-rose-600/10 transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100">
                    <Maximize2 className="text-rose-600" size={32} />
                    </div>
                </div>
                <div className="p-5 space-y-2 flex-1 flex flex-col">
                    <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest bg-rose-50 px-3 py-1 rounded-full border border-rose-100 w-fit">{item.category}</span>
                    <h4 className="font-bold text-slate-800 line-clamp-2 leading-tight uppercase text-xs tracking-tight flex-1">{item.related[0].questionText}</h4>
                    <div className="pt-2 flex items-center justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <span>{item.related.length} Map Points</span>
                    <ChevronRight size={14} />
                    </div>
                </div>
                </div>
            ))}
            </div>

            {visibleLimit < atlasItems.length && (
                <div className="mt-8 flex justify-center pb-8">
                    <button 
                        onClick={() => setVisibleLimit(prev => prev + 24)}
                        className="px-8 py-3 bg-white border-2 border-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest hover:border-slate-400 hover:text-slate-900 transition-all flex items-center gap-2 shadow-sm"
                    >
                        Load More Diagrams <ChevronDown size={14} />
                    </button>
                </div>
            )}
            </>
        ) : (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
                <MapIcon size={48} className="text-slate-300" />
                <p className="font-bold text-slate-400">No Atlas Entries Found</p>
            </div>
        )}
      </div>

      {/* Interactive Detail Modal */}
      {activeEntry && (
        <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex flex-col md:flex-row animate-in fade-in duration-300">
          <button onClick={() => setSelectedImage(null)} className="absolute top-6 right-6 z-[110] p-4 bg-white/10 hover:bg-white/20 rounded-2xl text-white transition-all shadow-2xl backdrop-blur-md border border-white/10">
            <X size={24} />
          </button>

          {/* Visualization Zone */}
          <div className="flex-[1.5] h-1/2 md:h-full flex items-center justify-center p-8 md:p-16 border-b md:border-b-0 md:border-r border-white/10 relative overflow-hidden">
            <div className="absolute inset-0 bg-rose-600/5 opacity-50 blur-3xl pointer-events-none"></div>
            <img src={cleanImageUrl(activeEntry.url)} className="max-w-full max-h-full object-contain transition-all duration-700 hover:scale-[1.02]" alt="Active Diagram" />
          </div>

          {/* Dictionary Zone */}
          <div className="flex-1 h-1/2 md:h-full bg-white flex flex-col">
            <div className="p-6 md:p-8 border-b border-slate-100 space-y-2">
              <span className="text-[10px] font-black text-rose-600 uppercase tracking-[0.3em]">{activeEntry.category}</span>
              <h2 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase italic">Intelligence Map</h2>
            </div>
            <div className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar space-y-4 md:space-y-6">
              {activeEntry.related.map((point, pIdx) => {
                const isMistake = mistakesVault.includes(point.id);
                return (
                    <div key={pIdx} className={`group p-5 md:p-6 rounded-[2rem] border transition-all ${isMistake ? 'border-amber-200 bg-amber-50/50' : 'border-slate-100 bg-slate-50/30 hover:bg-white hover:shadow-xl border-l-4 border-l-rose-100 hover:border-l-rose-600'}`}>
                    <div className="flex justify-between items-start mb-3">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <Info size={12} className={isMistake ? "text-amber-500" : "text-rose-500"} /> Point {pIdx + 1}
                        </h4>
                        {isMistake && (
                            <div className="flex items-center gap-2">
                                <span className="text-[9px] font-black uppercase text-amber-600 bg-amber-100 px-2 py-1 rounded">Active Mistake</span>
                                <button 
                                    onClick={(e) => handleResolveMistake(point.id, e)}
                                    className="p-1.5 bg-emerald-100 text-emerald-600 rounded-full hover:bg-emerald-500 hover:text-white transition-colors"
                                    title="Mark Resolved"
                                >
                                    <CheckCircle2 size={14} />
                                </button>
                            </div>
                        )}
                    </div>
                    <p className="text-base md:text-lg font-bold text-slate-800 leading-snug mb-3" dangerouslySetInnerHTML={{ __html: point.questionText }} />
                    <div className={`${isMistake ? 'bg-amber-100 border-amber-200' : 'bg-rose-50 border-rose-100'} px-4 py-3 rounded-xl border inline-block`}>
                        <span className={`font-black uppercase text-[10px] block mb-1 opacity-50 ${isMistake ? 'text-amber-800' : 'text-rose-600'}`}>Validation</span>
                        <span className="text-sm md:text-base font-black text-slate-900" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                    </div>
                    </div>
                );
              })}
            </div>
            <div className="p-6 bg-slate-900 text-white/50 text-[10px] font-bold uppercase tracking-widest text-center pb-safe">
              Internal Atlas Registry v.2025 • End of Record
            </div>
          </div>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Filters"
      />
    </div>
  );
};

export default InteractiveAtlas;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, Check, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  BookOpen
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isShuffled, setIsShuffled] = useState(false);
  const [isReversed, setIsReversed] = useState(false); // Reverse Q/A

  // Filter States
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Mistakes Vault Logic
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Are you sure you want to permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Filtered Data
  const activeData = useMemo(() => {
    let filtered = data;

    // 1. Filter by Mistakes First (if active)
    if (showMistakesOnly) {
      filtered = filtered.filter(q => mistakesVault.includes(q.id));
    }

    // 2. Filter by Images
    if (showImagesOnly) {
      filtered = filtered.filter(q => q.questionImage || q.answerImage);
    }

    // 3. Filter by Category (works with Mistakes mode now)
    if (selectedCategories.length > 0) {
      filtered = filtered.filter(q => selectedCategories.includes(q.category));
    }

    // 4. Shuffle
    if (isShuffled) {
      return [...filtered].sort(() => Math.random() - 0.5);
    }

    return filtered;
  }, [data, showImagesOnly, selectedCategories, isShuffled, showMistakesOnly, mistakesVault]);

  // Reset index when data changes
  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [activeData.length, isShuffled, showMistakesOnly, selectedCategories, showImagesOnly]);

  // PERFORMANCE: Preload Next Card Images
  useEffect(() => {
    if (currentIndex < activeData.length - 1) {
        const nextCard = activeData[currentIndex + 1];
        if (nextCard.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextCard.questionImage);
        }
        if (nextCard.answerImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextCard.answerImage);
        }
    }
  }, [currentIndex, activeData]);

  const currentCard = activeData[currentIndex];

  // Determine content based on Reversal State
  const frontContent = isReversed ? {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  } : {
    label: 'Question',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  } : {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  };

  const handleNext = () => {
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) {
      cancel();
    } else {
      speak(text, currentCard.id + suffix);
    }
  };

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Cards`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => setShowMistakesOnly(!showMistakesOnly),
        colorTheme: 'amber'
    },
    {
        label: 'Visuals Only',
        subLabel: 'Diagrams',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => setShowImagesOnly(!showImagesOnly),
        colorTheme: 'indigo'
    }
  ];

  // Empty State
  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-in fade-in zoom-in-95 duration-500">
        <div className={`p-6 rounded-full ${showMistakesOnly ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-2">
            <h3 className="text-2xl font-black text-slate-800">
                {showMistakesOnly ? "Vault Cleared!" : "No Flashcards Found"}
            </h3>
            <p className="text-slate-500 font-medium max-w-xs mx-auto">
                {showMistakesOnly 
                    ? "Excellent work! You've resolved all recorded mistakes." 
                    : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-rose-600 transition-colors shadow-lg"
        >
          Reset All Filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Controls & Header */}
      <div className="flex flex-col md:flex-row justify-between items-center px-4 py-4 gap-4">
        <div className="flex items-center gap-2 w-full md:w-auto">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`p-3 rounded-xl border-2 transition-all flex items-center gap-2 ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter size={20} />
             {(selectedCategories.length > 0 || showImagesOnly || showMistakesOnly) && (
                 <span className="text-[10px] font-black bg-rose-600 text-white px-1.5 py-0.5 rounded-md">
                    {[selectedCategories.length > 0, showImagesOnly, showMistakesOnly].filter(Boolean).length}
                 </span>
             )}
           </button>

           <div className="flex-1 md:flex-none flex flex-col justify-center px-2">
              <h2 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-1">
                {showMistakesOnly ? <><AlertTriangle size={12} className="text-amber-500" /> Mistakes Vault</> : <><BookOpen size={12} /> Study Deck</>}
              </h2>
              <span className="text-[10px] font-bold text-slate-300">
                Card {currentIndex + 1} of {activeData.length}
              </span>
           </div>
        </div>

        <div className="flex items-center gap-2 w-full md:w-auto justify-end">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`p-3 rounded-xl border-2 transition-all ${isReversed ? 'border-emerald-500 bg-emerald-50 text-emerald-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
             title="Reverse Card Sides"
           >
             <ArrowLeftRight size={20} />
           </button>
           <button 
             onClick={() => setIsShuffled(!isShuffled)}
             className={`p-3 rounded-xl border-2 transition-all ${isShuffled ? 'border-purple-500 bg-purple-50 text-purple-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Shuffle size={20} />
           </button>
        </div>
      </div>

      {/* Card Area */}
      <div className="flex-1 px-4 pb-4 md:pb-8 flex flex-col justify-center min-h-0">
        <div 
          className="relative w-full h-full perspective-1000 group cursor-pointer"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front Face */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border-2 border-slate-100 p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar">
               <div className="w-full flex justify-between items-start mb-4 shrink-0">
                   <span className={`text-[10px] font-black uppercase tracking-[0.3em] ${isReversed ? 'text-emerald-500' : 'text-slate-300'}`}>
                     {frontContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-rose-500 uppercase tracking-widest bg-rose-50 px-2 py-1 rounded-lg border border-rose-100">
                           <AlertTriangle size={10} /> Mistake
                       </div>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full">
                 {frontContent.image && (
                   <div className="mb-8 max-h-[30vh] flex items-center justify-center shrink-0">
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <h2 className={`text-xl md:text-3xl font-black leading-tight mb-6 break-words hyphens-auto w-full ${isReversed ? 'text-emerald-600' : 'text-slate-800'}`} dangerouslySetInnerHTML={{ __html: frontContent.text || '' }} />

                 {/* Explanation on Front if it's the Answer side (Reversed Mode) */}
                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-5 bg-emerald-50 rounded-2xl border border-emerald-100 text-left mt-4 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <span className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest block mb-2">Clinical Note</span>
                     <p className="text-sm font-medium text-emerald-800 leading-relaxed break-words" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-4 shrink-0">
                 <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest truncate max-w-[70%] text-left">{currentCard.category}</div>
                 <div className="flex items-center gap-3">
                    {/* Resolve Button (Only in Mistakes Mode & Answer Side) */}
                    {showMistakesOnly && !frontContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-4 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-500 hover:text-white transition-all shadow-sm border border-emerald-100"
                            title="Mastered - Remove from Mistakes"
                        >
                            <CheckCircle2 size={24} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, frontContent.text || '', '-front')}
                        className="p-4 bg-slate-50 rounded-full text-slate-400 hover:bg-rose-50 hover:text-rose-600 transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-front') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                    </button>
                 </div>
               </div>
            </div>

            {/* Back Face */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2.5rem] shadow-2xl p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar text-white">
               <div className="w-full flex justify-between items-start mb-4 shrink-0">
                   <span className={`text-[10px] font-black uppercase tracking-[0.3em] ${isReversed ? 'text-slate-400' : 'text-emerald-400'}`}>
                     {backContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-rose-300 uppercase tracking-widest bg-white/10 px-2 py-1 rounded-lg">
                           <AlertTriangle size={10} /> Mistake
                       </div>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full">
                 {backContent.image && (
                   <div className="mb-8 max-h-[30vh] flex items-center justify-center shrink-0">
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg bg-white/5" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <p className={`text-xl md:text-3xl font-bold leading-relaxed mb-6 break-words hyphens-auto w-full ${isReversed ? 'text-white' : 'text-emerald-400'}`} dangerouslySetInnerHTML={{ __html: backContent.text || '' }} />

                 {/* Explanation on Back if it's the Answer side (Normal Mode) */}
                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-5 bg-white/5 rounded-2xl border border-white/10 text-left mt-4 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Clinical Note</span>
                     <p className="text-sm font-medium text-slate-300 leading-relaxed break-words" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-4 shrink-0">
                 <div className="text-[10px] font-bold text-slate-600 uppercase tracking-widest truncate max-w-[70%] text-left">{currentCard.category}</div>
                 <div className="flex items-center gap-3">
                    {/* Resolve Button (Only in Mistakes Mode & Answer Side) */}
                    {showMistakesOnly && !backContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-4 bg-emerald-500/20 text-emerald-400 rounded-full hover:bg-emerald-500 hover:text-white transition-all shadow-sm border border-emerald-500/30"
                            title="Mastered - Remove from Mistakes"
                        >
                            <CheckCircle2 size={24} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, backContent.text || '', '-back')}
                        className="p-4 bg-white/10 rounded-full text-slate-400 hover:bg-white/20 hover:text-white transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-back') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                    </button>
                 </div>
               </div>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="px-8 pb-32 md:pb-12 pt-2 flex justify-center gap-6">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="w-16 h-16 rounded-2xl bg-white border-2 border-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-30 hover:border-slate-300 hover:text-slate-600 transition-all shadow-sm"
        >
          <ArrowLeft size={24} strokeWidth={3} />
        </button>

        <button 
          onClick={() => setIsFlipped(!isFlipped)} 
          className="h-16 px-10 rounded-2xl bg-rose-600 text-white font-black uppercase tracking-widest text-xs hover:bg-rose-700 transition-all shadow-xl shadow-rose-200 flex items-center gap-3"
        >
          <RotateCcw size={18} /> Flip Card
        </button>

        <button 
          onClick={handleNext} 
          disabled={currentIndex === activeData.length - 1}
          className="w-16 h-16 rounded-2xl bg-white border-2 border-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-30 hover:border-slate-300 hover:text-slate-600 transition-all shadow-sm"
        >
          <ArrowRight size={24} strokeWidth={3} />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

export default Flashcards;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport }) => {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState(''); // New state for performance
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Sync with LocalStorage whenever mistakesVault changes
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the mistakes vault?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire mistakes history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-6">
      {/* Search Header */}
      <div className={`rounded-[2.5rem] p-8 md:p-12 mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h2 className="text-3xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Mistakes" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Vault" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
