import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as ch12 } from './hooks/data_ch12';
import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';

import { Trash2, Activity, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  // Ensure header is visible when changing modes
  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // Final Data Merge Engine
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    // 1. Collect all raw sources
    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    // 2. Build Smart Distractor Pools (Per Chapter/Category)
    // This allows us to generate realistic wrong answers if a question is missing options
    const categoryAnswerPools: Record<string, string[]> = {};
    sources.forEach(q => {
        if (!categoryAnswerPools[q.category]) categoryAnswerPools[q.category] = [];
        // Only use reasonably short answers as distractors to keep UI clean
        if (q.answerText && q.answerText.length < 150) {
            categoryAnswerPools[q.category].push(q.answerText);
        }
    });

    sources.forEach(q => {
        // FILTER: Remove low quality/placeholder questions
        const isLowQuality = 
            q.questionText.includes('Part ') || 
            q.answerText.includes('Node ') || 
            q.questionText.includes('Study Point') ||
            (q.questionText.length < 10 && !q.questionImage);

        if (!seenIds.has(q.id) && !isLowQuality) {

            // OPTION REPAIR LOGIC
            let finalOptions = q.options ? [...q.options] : [];

            // Case A: Question has NO options or only 1 option (the answer)
            // We need to generate distractors.
            if (finalOptions.length < 2) {
                const pool = categoryAnswerPools[q.category] || [];
                // Pick 3 random answers from the same chapter that aren't the correct answer
                const randomDistractors = pool
                    .filter(a => a !== q.answerText)
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];

                // Fallback if pool is empty: Generic options (Last resort)
                if (finalOptions.length < 2) {
                    finalOptions = [q.answerText, "Option A", "Option B", "Option C"];
                }
            }

            // Case B: Question HAS options (e.g., True/False or MCQ)
            // Just ensure the correct answer is actually IN the list.
            if (!finalOptions.includes(q.answerText)) {
                // If missing, replace the first option with the correct one
                finalOptions[0] = q.answerText;
            }

            // Deduplicate options
            finalOptions = Array.from(new Set(finalOptions));

            const finalQ = {
              ...q,
              options: finalOptions
            };

            uniqueQuestions.push(finalQ);
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-y-auto overflow-x-hidden font-sans text-slate-900">
         {/* Background effects */}
         <div className="absolute inset-0 bg-[radial-gradient(#cbd5e1_1px,transparent_1px)] [background-size:24px_24px] opacity-50"></div>
         <div className="absolute top-[-10%] right-[-10%] w-[60vw] h-[60vw] bg-rose-500/10 rounded-full blur-3xl pointer-events-none"></div>
         <div className="absolute bottom-[-10%] left-[-10%] w-[60vw] h-[60vw] bg-slate-900/5 rounded-full blur-3xl pointer-events-none"></div>

         <div className="relative z-10 flex flex-col items-center text-center space-y-8 max-w-md w-full my-auto">
            <div className="w-24 h-24 bg-white rounded-[2rem] shadow-2xl flex items-center justify-center border-4 border-slate-50 animate-in zoom-in duration-700">
               <Activity size={48} className="text-rose-500" strokeWidth={2.5} />
            </div>

            <div className="space-y-2 animate-in slide-in-from-bottom-4 duration-700 delay-100">
               <div className="inline-block px-3 py-1 rounded-full bg-slate-200/50 border border-slate-300/50 text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">
                  Occupational Therapy
               </div>
               <h1 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight font-display leading-[0.9]">
                  Anatomy <br/> <span className="text-rose-500">&</span> Physiology
               </h1>
               <p className="text-slate-400 font-bold text-sm tracking-wide mt-2">
                  Professional Study Vault v.5
               </p>
            </div>

            <button 
              onClick={() => setHasStarted(true)}
              className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-[0.2em] text-sm shadow-2xl hover:bg-rose-600 hover:shadow-rose-200/50 transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-700 delay-200 group relative overflow-hidden"
            >
               <span className="relative z-10 flex items-center justify-center gap-2">
                 Start Learning <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform"/>
               </span>
            </button>
         </div>

         <div className="mt-8 md:absolute md:bottom-8 text-center animate-in fade-in duration-1000 delay-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest opacity-60">
               Designed for OT Students
            </p>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden fixed inset-0">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-500 ${isHeaderVisible ? 'pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full rounded-t-[2.5rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl shadow-slate-200/50 border border-white/50 backdrop-blur-sm bg-white/40 relative z-10 transition-all duration-500 ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-in fade-in slide-in-from-bottom-4 duration-700 pb-28 md:pb-0">
                <Flashcards data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-in fade-in slide-in-from-right-4 duration-500 pb-28 md:pb-0">
                <InteractiveAtlas data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-in zoom-in-95 duration-500 pb-28 md:pb-0">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6">
                <QuestionList 
                  data={allQuestions} 
                  onExport={() => {}} 
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                        <Trash2 size={12} className="inline mr-1" /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      {/* New Mobile Bottom Navigation - Floating */}
      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

