// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => {
  return text.replace(/^(Option|Part)\s+/i, '').trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader }) => {
  // --- PERSISTENCE LOGIC ---
  const savedState = useMemo(() => {
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, []);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(savedState?.view || 'setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(savedState?.mode || 'exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // Save Progress Automatically
  useEffect(() => {
    if (view === 'playing' || view === 'results' || view === 'review') {
      localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({
        view, questions, currentQIndex, timeLeft, mode
      }));
    } else {
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
    }
  }, [view, questions, currentQIndex, timeLeft, mode]);

  // Handle Header Visibility
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      toggleHeader?.(false);
    } else {
      toggleHeader?.(true);
    }
  }, [view, toggleHeader]);

  // Responsive Sidebar
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024) {
            setIsSidebarOpen(false);
        } else {
            setIsSidebarOpen(true);
        }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); // Init
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    // Scroll to top of question when changing
    if (questionRef.current) {
        questionRef.current.scrollTop = 0;
    }
  }, [currentQIndex, view]);

  // Preload next image
  useEffect(() => {
    if (view === 'playing' && questions.length > 0 && currentQIndex < questions.length - 1) {
        const nextQ = questions[currentQIndex + 1];
        if (nextQ.data.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextQ.data.questionImage);
        }
    }
  }, [currentQIndex, questions, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      // 1. Use existing options if they exist and we have enough (>= 2, e.g. True/False)
      let finalOptions = q.options && q.options.length >= 2 ? [...q.options] : [q.answerText];

      // 2. ONLY generate distractors if we have < 2 options (i.e. we only have the answer)
      if (finalOptions.length < 2) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText && item.answerText.length < 150)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 3); // Aim for 3 distractors

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Failsafe: if we still don't have enough options, add generics
        while(finalOptions.length < 2) { // At least 2 are needed to be a valid question
           finalOptions.push("False"); // Fallback for T/F or similar
        }
      }

      // 3. Shuffle options (so answer isn't always first)
      return {
        id: q.id, 
        data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);
    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    setView('results');
  };

  const saveAndExit = (resolveCorrect: boolean) => {
    const wrongIds = questions.filter(q => q.userAnswer !== q.correctOption).map(q => q.id);
    const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
        let next = [...prev];
        if (wrongIds.length > 0) next = [...next, ...wrongIds];
        if (resolveCorrect) next = next.filter(id => !correctIds.includes(id));
        return Array.from(new Set(next));
    });

    localStorage.removeItem('OT_QUIZ_SESSION_V5');
    setView('setup');
    toggleHeader?.(true);
  };

  const retrySession = () => {
    const resetQuestions = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
    const reshuffled = [...resetQuestions].sort(() => Math.random() - 0.5);
    setQuestions(reshuffled);
    setCurrentQIndex(0);
    setTimeLeft(reshuffled.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const retryIncorrectOnly = () => {
    const wrongQuestions = questions
        .filter(q => q.userAnswer !== q.correctOption)
        .map(q => ({...q, userAnswer: null, isFlagged: false}));

    if (wrongQuestions.length === 0) return;

    setQuestions(wrongQuestions.sort(() => Math.random() - 0.5));
    setCurrentQIndex(0);
    setTimeLeft(wrongQuestions.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const exitQuiz = () => {
    if (confirm("End current exam session? Progress will be lost.")) {
      cancel();
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Mode',
        icon: ImageIcon,
        isActive: showDiagramsOnly,
        onClick: () => setShowDiagramsOnly(!showDiagramsOnly),
        colorTheme: 'indigo'
    }
  ];

  // --- VIEW: SETUP ---
  if (view === 'setup') {
    let filteredPool = data;
    if (mode === 'mistakes') filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    const maxQuestions = filteredPool.length;

    if (questionCount > maxQuestions && maxQuestions > 0) setQuestionCount(maxQuestions);

    return (
      <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar relative">
          <div className="min-h-full flex flex-col items-center justify-center p-4 pb-32 md:pb-10">
             <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500">
                {/* Header */}
                <div className="bg-slate-900 p-6 md:p-8 text-white relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-10">
                        <Monitor size={120} />
                    </div>
                    <h2 className="text-xl md:text-2xl font-display font-bold tracking-tight mb-2">Exam Configuration</h2>
                    <p className="text-slate-400 text-xs md:text-sm font-medium">Occupational Therapy Department • Anatomy V.5</p>
                </div>

                <div className="p-6 md:p-8 space-y-6 md:space-y-8">
                    {/* Mode Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4">
                    {[
                        { id: 'exam', label: 'University Exam', sub: 'Timed • No Hints', icon: Clock, color: 'rose' },
                        { id: 'practice', label: 'Study Mode', sub: 'Instant Feedback', icon: Zap, color: 'blue' },
                        { id: 'mistakes', label: 'Error Vault', sub: `${mistakesVault.length} items`, icon: AlertTriangle, color: 'amber' }
                    ].map((m) => (
                        <button 
                        key={m.id}
                        onClick={() => setMode(m.id as any)}
                        className={`p-4 rounded-xl border-2 transition-all text-left flex flex-col gap-3 ${mode === m.id 
                            ? `border-${m.color}-500 bg-${m.color}-50 text-${m.color}-900` 
                            : 'border-slate-100 hover:border-slate-300 text-slate-500'}`}
                        >
                            <div className={`p-2 rounded-lg w-fit ${mode === m.id ? `bg-${m.color}-200 text-${m.color}-700` : 'bg-slate-100'}`}>
                                <m.icon size={20} />
                            </div>
                            <div>
                                <span className="block font-bold text-sm">{m.label}</span>
                                <span className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{m.sub}</span>
                            </div>
                        </button>
                    ))}
                    </div>

                    <div className="space-y-6 border-t border-slate-100 pt-6">
                        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                            <button 
                                onClick={() => setIsBankModalOpen(true)}
                                className={`flex-1 w-full p-4 rounded-xl border-2 flex items-center justify-between transition-all ${selectedCategories.length > 0 ? 'border-slate-800 bg-slate-800 text-white' : 'border-slate-200 hover:border-slate-300 text-slate-600'}`}
                            >
                                <div className="flex items-center gap-3">
                                    <List size={18} />
                                    <div className="text-left">
                                        <span className="block text-xs font-black uppercase tracking-widest">Content Source</span>
                                        <span className="block text-sm font-bold truncate max-w-[200px]">
                                            {selectedCategories.length === 0 ? "All Chapters (Comprehensive)" : `${selectedCategories.length} Modules Selected`}
                                        </span>
                                    </div>
                                </div>
                                <ChevronRight size={16} />
                            </button>

                            <div className="flex-1 w-full space-y-2">
                                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-widest px-1">
                                    <span>Question Limit</span>
                                    <span>{questionCount} / {maxQuestions}</span>
                                </div>
                                <input 
                                    type="range" 
                                    min="1" 
                                    max={maxQuestions || 1} 
                                    value={questionCount}
                                    disabled={maxQuestions === 0}
                                    onChange={(e) => setQuestionCount(Number(e.target.value))}
                                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900"
                                />
                            </div>
                        </div>
                    </div>

                    <button 
                    onClick={startSession}
                    disabled={maxQuestions === 0}
                    className="w-full py-4 bg-slate-900 hover:bg-rose-600 text-white rounded-xl font-bold text-sm uppercase tracking-widest shadow-xl hover:shadow-2xl transition-all hover:-translate-y-1 active:translate-y-0 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
                    >
                    <span>Start Exam</span>
                    <ChevronRight size={18} />
                    </button>
                </div>
             </div>
          </div>

          <FilterModal
            isOpen={isBankModalOpen}
            onClose={() => setIsBankModalOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setShowDiagramsOnly(false); }}
            mainOptions={filterOptions}
            title="Curriculum Selection"
        />
      </div>
    );
  }

  // --- VIEW: PLAYING (The "Exam Paper" Look) ---
  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900">

        {/* Top Information Bar */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-slate-900 text-white rounded-lg flex items-center justify-center font-black text-xl">
                    OT
                </div>
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Anatomy & Physiology</h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{isPracticeMode ? 'Formative Assessment' : 'Summative Exam'}</p>
                </div>
            </div>

            <div className="flex items-center gap-6">
                {mode === 'exam' ? (
                    <div className={`flex items-center gap-2 px-4 py-2 rounded-md font-mono font-bold text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-100 text-slate-700 border-slate-200'}`}>
                        <Clock size={18} /> {formatTime(timeLeft)}
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <span className="px-3 py-1 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-md text-xs font-bold flex items-center gap-1"><Check size={12} /> {questions.filter(q => q.userAnswer === q.correctOption).length}</span>
                        <span className="px-3 py-1 bg-rose-50 text-rose-700 border border-rose-200 rounded-md text-xs font-bold flex items-center gap-1"><X size={12} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</span>
                    </div>
                )}

                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-md transition-colors lg:hidden">
                    <LayoutGrid size={20} className="text-slate-500" />
                </button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden">

            {/* Main Question Paper */}
            <main className="flex-1 flex flex-col relative min-w-0">
                {/* Progress Strip */}
                <div className="h-1 bg-slate-200 w-full">
                    <div 
                        className="h-full bg-slate-900 transition-all duration-300" 
                        style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                    />
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white min-h-[500px] shadow-sm border border-slate-200 rounded-xl overflow-hidden">

                        {/* Question Header */}
                        <div className="bg-slate-50 border-b border-slate-100 p-6 flex justify-between items-start">
                            <div className="flex flex-col gap-1">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question {currentQIndex + 1} of {questions.length}</span>
                                <span className="text-xs font-bold text-slate-500 bg-white border border-slate-200 px-2 py-1 rounded w-fit">{currentQ.data.category}</span>
                            </div>
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => setQuestions(prev => {
                                        const c = [...prev];
                                        c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged;
                                        return c;
                                    })}
                                    className={`p-2 rounded-md border transition-all ${currentQ.isFlagged ? 'bg-amber-100 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                    title="Mark for Review"
                                >
                                    <Flag size={18} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                                </button>
                                <button 
                                    onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                                    className={`p-2 rounded-md border transition-all ${isSpeaking ? 'bg-blue-100 text-blue-600 border-blue-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                >
                                    <Volume2 size={18} />
                                </button>
                            </div>
                        </div>

                        <div className="p-8 md:p-10 space-y-8">
                            {/* Stem */}
                            <h2 className="text-xl md:text-2xl font-serif font-medium text-slate-900 leading-relaxed">
                                <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                            </h2>

                            {/* Image */}
                            {currentQ.data.questionImage && !imgError && (
                                <div className="border border-slate-200 rounded-lg p-2 bg-slate-50 inline-block max-w-full">
                                    <img 
                                        src={cleanImageUrl(currentQ.data.questionImage)} 
                                        alt="Clinical Figure" 
                                        className="max-h-[400px] w-auto object-contain rounded"
                                        onError={() => setImgError(true)}
                                    />
                                </div>
                            )}

                            {/* Options */}
                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const isCorrect = isPracticeMode && currentQ.userAnswer && opt === currentQ.correctOption;
                                    const isWrong = isPracticeMode && currentQ.userAnswer && isSelected && opt !== currentQ.correctOption;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;

                                    let containerStyle = "border-slate-200 hover:border-slate-400 hover:bg-slate-50 cursor-pointer";
                                    let circleStyle = "border-slate-300 text-slate-400";

                                    if (showAnswer) {
                                        if (isCorrect) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/50 cursor-default";
                                            circleStyle = "bg-emerald-500 border-emerald-500 text-white";
                                        } else if (isWrong) {
                                            containerStyle = "border-rose-500 bg-rose-50/50 cursor-default";
                                            circleStyle = "bg-rose-500 border-rose-500 text-white";
                                        } else if (opt === currentQ.correctOption) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/20 cursor-default"; // Show correct if missed
                                            circleStyle = "border-emerald-500 text-emerald-600";
                                        } else {
                                            containerStyle = "border-slate-100 text-slate-400 cursor-default opacity-60";
                                        }
                                    } else if (isSelected) {
                                        containerStyle = "border-slate-900 bg-slate-50 shadow-sm ring-1 ring-slate-900";
                                        circleStyle = "bg-slate-900 border-slate-900 text-white";
                                    }

                                    return (
                                        <div 
                                            key={i}
                                            onClick={() => {
                                                if (showAnswer) return;
                                                setQuestions(prev => {
                                                    const c = [...prev];
                                                    c[currentQIndex].userAnswer = opt;
                                                    return c;
                                                });
                                            }}
                                            className={`group relative flex items-start gap-4 p-4 rounded-lg border transition-all duration-200 ${containerStyle}`}
                                        >
                                            <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 transition-colors ${circleStyle}`}>
                                                {showAnswer && isCorrect ? <Check size={14} /> : showAnswer && isWrong ? <X size={14} /> : letter}
                                            </div>
                                            <div className="flex-1 text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-6 rounded-lg border-l-4 text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500 text-emerald-900' : 'bg-slate-100 border-slate-400 text-slate-800'}`}>
                                    <h4 className="font-bold uppercase tracking-widest text-xs mb-2 opacity-70">
                                        {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                    </h4>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No additional clinical notes available." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Controls */}
                <div className="bg-white border-t border-slate-200 p-4 flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-20">
                    <button 
                        onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))}
                        disabled={currentQIndex === 0}
                        className="flex items-center gap-2 px-6 py-3 rounded-lg font-bold text-xs uppercase tracking-widest text-slate-600 hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                    >
                        <ChevronLeft size={16} /> Previous
                    </button>

                    <button 
                        onClick={() => {
                            if (currentQIndex === questions.length - 1) {
                                handleFinish();
                            } else {
                                setCurrentQIndex(prev => prev + 1);
                                setImgError(false);
                            }
                        }}
                        className="flex items-center gap-2 px-8 py-3 rounded-lg font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg hover:shadow-xl transition-all hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {currentQIndex === questions.length - 1 ? 'Submit Exam' : 'Next Question'} 
                        {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}
                    </button>
                </div>
            </main>

            {/* Sidebar (Question Palette) */}
            <aside className={`bg-white border-l border-slate-200 w-80 flex-col shrink-0 transition-transform duration-300 absolute lg:relative inset-y-0 right-0 z-40 lg:translate-x-0 shadow-2xl lg:shadow-none ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'} flex`}>
                <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                    <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400"><X size={20} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
                    <div className="grid grid-cols-5 gap-2">
                        {questions.map((q, i) => {
                            let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-400";
                            if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200";
                            else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-600";
                            else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";

                            return (
                                <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }}
                                    className={`aspect-square rounded flex items-center justify-center text-xs font-medium border transition-all relative group ${style}`}
                                >
                                    {i + 1}
                                    {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="p-5 border-t border-slate-200 bg-slate-50 space-y-3">
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-slate-800 rounded"></div> Current
                    </div>
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
