                                    <h3 className="font-medium text-slate-900 leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />

                                    {q.data.questionImage && (
                                        <div className="p-2 border border-slate-100 bg-slate-50 rounded-lg w-fit">
                                            <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 rounded" alt="ref" />
