                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                                        <div className={`p-3 rounded-lg border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}>
                                            <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Your Selection</span>
                                            <span className="font-bold" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} />
                                        </div>
                                        {q.userAnswer !== q.correctOption && (
                                            <div className="p-3 rounded-lg border bg-slate-50 border-slate-200 text-slate-900">
                                                <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Correct Answer</span>
                                                <span className="font-bold" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

