        ) : (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
                <MapIcon size={48} className="text-slate-300" />
                <p className="font-bold text-slate-400">No Atlas Entries Found</p>
            </div>
        )}
      </div>

      {/* Interactive Detail Modal - RESPONSIVE LAYOUT */}
      {activeEntry && (
        <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex flex-col md:flex-row animate-in fade-in duration-300">
          <button onClick={() => setSelectedImage(null)} className="absolute top-4 right-4 md:top-6 md:right-6 z-[120] p-3 md:p-4 bg-white/10 hover:bg-white/20 rounded-2xl text-white transition-all shadow-2xl backdrop-blur-md border border-white/10">
            <X size={20} />
          </button>

          {/* Visualization Zone */}
          <div className="h-[40vh] md:h-full md:flex-[1.5] flex items-center justify-center p-4 md:p-16 border-b md:border-b-0 md:border-r border-white/10 relative overflow-hidden bg-black/20">
            <div className="absolute inset-0 bg-rose-600/5 opacity-50 blur-3xl pointer-events-none"></div>
            <img src={cleanImageUrl(activeEntry.url)} className="max-w-full max-h-full object-contain transition-all duration-700 hover:scale-[1.02]" alt="Active Diagram" />
          </div>

          {/* Dictionary Zone */}
          <div className="flex-1 h-[60vh] md:h-full bg-white flex flex-col rounded-t-[2.5rem] md:rounded-none overflow-hidden shadow-2xl md:shadow-none">
            <div className="p-6 md:p-8 border-b border-slate-100 space-y-2 bg-white sticky top-0 z-10">
              <span className="text-[10px] font-black text-rose-600 uppercase tracking-[0.3em] block truncate">{activeEntry.category}</span>
              <h2 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase italic">Intelligence Map</h2>
            </div>
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 md:space-y-6 pb-safe">
              {activeEntry.related.map((point, pIdx) => {
                const isMistake = mistakesVault.includes(point.id);
                return (
                    <div key={pIdx} className={`group p-5 md:p-6 rounded-[2rem] border transition-all ${isMistake ? 'border-amber-200 bg-amber-50/50' : 'border-slate-100 bg-slate-50/30 hover:bg-white hover:shadow-xl border-l-4 border-l-rose-100 hover:border-l-rose-600'}`}>
                    <div className="flex justify-between items-start mb-3">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <Info size={12} className={isMistake ? "text-amber-500" : "text-rose-500"} /> Point {pIdx + 1}
                        </h4>
                        {isMistake && (
                            <div className="flex items-center gap-2">
                                <span className="text-[9px] font-black uppercase text-amber-600 bg-amber-100 px-2 py-1 rounded">Active Mistake</span>
                                <button 
                                    onClick={(e) => handleResolveMistake(point.id, e)}
                                    className="p-1.5 bg-emerald-100 text-emerald-600 rounded-full hover:bg-emerald-500 hover:text-white transition-colors"
                                    title="Mark Resolved"
                                >
                                    <CheckCircle2 size={14} />
                                </button>
                            </div>
                        )}
                    </div>
                    <p className="text-sm md:text-lg font-bold text-slate-800 leading-snug mb-3" dangerouslySetInnerHTML={{ __html: point.questionText }} />
                    <div className={`${isMistake ? 'bg-amber-100 border-amber-200' : 'bg-rose-50 border-rose-100'} px-4 py-3 rounded-xl border inline-block w-full md:w-auto`}>
                        <span className={`font-black uppercase text-[10px] block mb-1 opacity-50 ${isMistake ? 'text-amber-800' : 'text-rose-600'}`}>Validation</span>
                        <span className="text-sm md:text-base font-black text-slate-900 break-words" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                    </div>
                    </div>
                );
              })}
              <div className="p-6 text-slate-300 text-[10px] font-bold uppercase tracking-widest text-center">
                End of Record
              </div>
            </div>
          </div>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Filters"
      />
    </div>
  );
};

export default InteractiveAtlas;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2, AlertTriangle, RotateCcw, XCircle,
  Play, Settings2, Send, Save, Trash2, Bookmark, Monitor, MoreVertical
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => {
  return text.replace(/^(Option|Part)\s+/i, '').trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader }) => {
  // --- PERSISTENCE LOGIC ---
  const savedState = useMemo(() => {
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, []);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(savedState?.view || 'setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(savedState?.mode || 'exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // Save Progress Automatically
  useEffect(() => {
    if (view === 'playing' || view === 'results' || view === 'review') {
      localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({
        view, questions, currentQIndex, timeLeft, mode
      }));
    } else {
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
    }
  }, [view, questions, currentQIndex, timeLeft, mode]);

  // Handle Header Visibility
  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      toggleHeader?.(false);
    } else {
      toggleHeader?.(true);
    }
  }, [view, toggleHeader]);

  // Responsive Sidebar
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024) {
            setIsSidebarOpen(false);
        } else {
            setIsSidebarOpen(true);
        }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); // Init
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    // Scroll to top of question when changing
    if (questionRef.current) {
        questionRef.current.scrollTop = 0;
    }
  }, [currentQIndex, view]);

  // Preload next image
  useEffect(() => {
    if (view === 'playing' && questions.length > 0 && currentQIndex < questions.length - 1) {
        const nextQ = questions[currentQIndex + 1];
        if (nextQ.data.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextQ.data.questionImage);
        }
    }
  }, [currentQIndex, questions, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {

      let finalOptions = q.options && q.options.length > 0 ? [...q.options] : [q.answerText];

      if (finalOptions.length === 1) {
         finalOptions.push('Option A', 'Option B', 'Option C'); 
      }

      finalOptions.sort(() => Math.random() - 0.5);

      return {
        id: q.id, 
        data: q,
        options: finalOptions,
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);
    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    setView('results');
  };

  const saveAndExit = (resolveCorrect: boolean) => {
    const wrongIds = questions.filter(q => q.userAnswer !== q.correctOption).map(q => q.id);
    const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
        let next = [...prev];
        if (wrongIds.length > 0) next = [...next, ...wrongIds];
        if (resolveCorrect) next = next.filter(id => !correctIds.includes(id));
        return Array.from(new Set(next));
    });

    localStorage.removeItem('OT_QUIZ_SESSION_V5');
    setView('setup');
    toggleHeader?.(true);
  };

  const retrySession = () => {
    const resetQuestions = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
    const reshuffled = [...resetQuestions].sort(() => Math.random() - 0.5);
    setQuestions(reshuffled);
    setCurrentQIndex(0);
    setTimeLeft(reshuffled.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const retryIncorrectOnly = () => {
    const wrongQuestions = questions
        .filter(q => q.userAnswer !== q.correctOption)
        .map(q => ({...q, userAnswer: null, isFlagged: false}));

    if (wrongQuestions.length === 0) return;

    setQuestions(wrongQuestions.sort(() => Math.random() - 0.5));
    setCurrentQIndex(0);
    setTimeLeft(wrongQuestions.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const exitQuiz = () => {
    if (confirm("End current exam session? Progress will be lost.")) {
      cancel();
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Mode',
        icon: ImageIcon,
        isActive: showDiagramsOnly,
        onClick: () => setShowDiagramsOnly(!showDiagramsOnly),
        colorTheme: 'indigo'
    }
  ];

  // --- VIEW: SETUP ---
  if (view === 'setup') {
    let filteredPool = data;
    if (mode === 'mistakes') filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    const maxQuestions = filteredPool.length;

    if (questionCount > maxQuestions && maxQuestions > 0) setQuestionCount(maxQuestions);

    return (
      <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar relative">
          <div className="min-h-full flex flex-col items-center justify-center p-4 pb-32 md:pb-10">
             <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500">
                {/* Header */}
                <div className="bg-slate-900 p-6 md:p-8 text-white relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-10">
                        <Monitor size={120} />
                    </div>
                    <h2 className="text-xl md:text-2xl font-display font-bold tracking-tight mb-2">Exam Configuration</h2>
                    <p className="text-slate-400 text-xs md:text-sm font-medium">Occupational Therapy Department • Anatomy V.5</p>
                </div>

                <div className="p-6 md:p-8 space-y-6 md:space-y-8">
                    {/* Mode Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4">
                    {[
                        { id: 'exam', label: 'University Exam', sub: 'Timed • No Hints', icon: Clock, color: 'rose' },
                        { id: 'practice', label: 'Study Mode', sub: 'Instant Feedback', icon: Zap, color: 'blue' },
                        { id: 'mistakes', label: 'Error Vault', sub: `${mistakesVault.length} items`, icon: AlertTriangle, color: 'amber' }
                    ].map((m) => (
                        <button 
                        key={m.id}
                        onClick={() => setMode(m.id as any)}
                        className={`p-4 rounded-xl border-2 transition-all text-left flex flex-col gap-3 ${mode === m.id 
                            ? `border-${m.color}-500 bg-${m.color}-50 text-${m.color}-900` 
                            : 'border-slate-100 hover:border-slate-300 text-slate-500'}`}
                        >
                            <div className={`p-2 rounded-lg w-fit ${mode === m.id ? `bg-${m.color}-200 text-${m.color}-700` : 'bg-slate-100'}`}>
                                <m.icon size={20} />
                            </div>
                            <div>
                                <span className="block font-bold text-sm">{m.label}</span>
                                <span className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{m.sub}</span>
                            </div>
                        </button>
                    ))}
                    </div>

                    <div className="space-y-6 border-t border-slate-100 pt-6">
                        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                            <button 
                                onClick={() => setIsBankModalOpen(true)}
                                className={`flex-1 w-full p-4 rounded-xl border-2 flex items-center justify-between transition-all ${selectedCategories.length > 0 ? 'border-slate-800 bg-slate-800 text-white' : 'border-slate-200 hover:border-slate-300 text-slate-600'}`}
                            >
                                <div className="flex items-center gap-3">
                                    <List size={18} />
                                    <div className="text-left">
                                        <span className="block text-xs font-black uppercase tracking-widest">Content Source</span>
                                        <span className="block text-sm font-bold truncate max-w-[200px]">
                                            {selectedCategories.length === 0 ? "All Chapters (Comprehensive)" : `${selectedCategories.length} Modules Selected`}
                                        </span>
                                    </div>
                                </div>
                                <ChevronRight size={16} />
                            </button>

                            <div className="flex-1 w-full space-y-2">
                                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-widest px-1">
                                    <span>Question Limit</span>
                                    <span>{questionCount} / {maxQuestions}</span>
                                </div>
                                <input 
                                    type="range" 
                                    min="1" 
                                    max={maxQuestions || 1} 
                                    value={questionCount}
                                    disabled={maxQuestions === 0}
                                    onChange={(e) => setQuestionCount(Number(e.target.value))}
                                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900"
                                />
                            </div>
                        </div>
                    </div>

                    <button 
                    onClick={startSession}
                    disabled={maxQuestions === 0}
                    className="w-full py-4 bg-slate-900 hover:bg-rose-600 text-white rounded-xl font-bold text-sm uppercase tracking-widest shadow-xl hover:shadow-2xl transition-all hover:-translate-y-1 active:translate-y-0 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
                    >
                    <span>Start Exam</span>
                    <ChevronRight size={18} />
                    </button>
                </div>
             </div>
          </div>

          <FilterModal
            isOpen={isBankModalOpen}
            onClose={() => setIsBankModalOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setShowDiagramsOnly(false); }}
            mainOptions={filterOptions}
            title="Curriculum Selection"
        />
      </div>
    );
  }

  // --- VIEW: PLAYING (The "Exam Paper" Look) ---
  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900">

        {/* Top Information Bar */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-slate-900 text-white rounded-lg flex items-center justify-center font-black text-xl">
                    OT
                </div>
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Anatomy & Physiology</h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{isPracticeMode ? 'Formative Assessment' : 'Summative Exam'}</p>
                </div>
            </div>

            <div className="flex items-center gap-4 md:gap-6">
                {mode === 'exam' ? (
                    <div className={`flex items-center gap-2 px-3 md:px-4 py-2 rounded-md font-mono font-bold text-base md:text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-100 text-slate-700 border-slate-200'}`}>
                        <Clock size={18} /> {formatTime(timeLeft)}
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <span className="px-3 py-1 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-md text-xs font-bold flex items-center gap-1"><Check size={12} /> {questions.filter(q => q.userAnswer === q.correctOption).length}</span>
                        <span className="px-3 py-1 bg-rose-50 text-rose-700 border border-rose-200 rounded-md text-xs font-bold flex items-center gap-1"><X size={12} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</span>
                    </div>
                )}

                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-md transition-colors lg:hidden">
                    <LayoutGrid size={20} className="text-slate-500" />
                </button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden relative">

            {/* Main Question Paper */}
            <main className="flex-1 flex flex-col relative min-w-0">
                {/* Progress Strip */}
                <div className="h-1 bg-slate-200 w-full">
                    <div 
                        className="h-full bg-slate-900 transition-all duration-300" 
                        style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                    />
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white min-h-[500px] shadow-sm border border-slate-200 rounded-xl overflow-hidden">

                        {/* Question Header */}
                        <div className="bg-slate-50 border-b border-slate-100 p-4 md:p-6 flex justify-between items-start">
                            <div className="flex flex-col gap-1 pr-4">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question {currentQIndex + 1} of {questions.length}</span>
                                <span className="text-xs font-bold text-slate-500 bg-white border border-slate-200 px-2 py-1 rounded w-fit max-w-[200px] truncate">{currentQ.data.category}</span>
                            </div>
                            <div className="flex gap-2 shrink-0">
                                <button 
                                    onClick={() => setQuestions(prev => {
                                        const c = [...prev];
                                        c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged;
                                        return c;
                                    })}
                                    className={`p-2 rounded-md border transition-all ${currentQ.isFlagged ? 'bg-amber-100 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                    title="Mark for Review"
                                >
                                    <Flag size={18} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                                </button>
                                <button 
                                    onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                                    className={`p-2 rounded-md border transition-all ${isSpeaking ? 'bg-blue-100 text-blue-600 border-blue-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                >
                                    <Volume2 size={18} />
                                </button>
                            </div>
                        </div>

                        <div className="p-6 md:p-10 space-y-6 md:space-y-8">
                            {/* Stem */}
                            <h2 className="text-lg md:text-2xl font-serif font-medium text-slate-900 leading-relaxed">
                                <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                            </h2>

                            {/* Image */}
                            {currentQ.data.questionImage && !imgError && (
                                <div className="border border-slate-200 rounded-lg p-2 bg-slate-50 inline-block max-w-full">
                                    <img 
                                        src={cleanImageUrl(currentQ.data.questionImage)} 
                                        alt="Clinical Figure" 
                                        className="max-h-[30vh] md:max-h-[400px] w-auto object-contain rounded"
                                        onError={() => setImgError(true)}
                                    />
                                </div>
                            )}

                            {/* Options */}
                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const isCorrect = isPracticeMode && currentQ.userAnswer && opt === currentQ.correctOption;
                                    const isWrong = isPracticeMode && currentQ.userAnswer && isSelected && opt !== currentQ.correctOption;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;

                                    let containerStyle = "border-slate-200 hover:border-slate-400 hover:bg-slate-50 cursor-pointer";
                                    let circleStyle = "border-slate-300 text-slate-400";

                                    if (showAnswer) {
                                        if (isCorrect) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/50 cursor-default";
                                            circleStyle = "bg-emerald-500 border-emerald-500 text-white";
                                        } else if (isWrong) {
                                            containerStyle = "border-rose-500 bg-rose-50/50 cursor-default";
                                            circleStyle = "bg-rose-500 border-rose-500 text-white";
                                        } else if (opt === currentQ.correctOption) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/20 cursor-default"; // Show correct if missed
                                            circleStyle = "border-emerald-500 text-emerald-600";
                                        } else {
                                            containerStyle = "border-slate-100 text-slate-400 cursor-default opacity-60";
                                        }
                                    } else if (isSelected) {
                                        containerStyle = "border-slate-900 bg-slate-50 shadow-sm ring-1 ring-slate-900";
                                        circleStyle = "bg-slate-900 border-slate-900 text-white";
                                    }

                                    return (
                                        <div 
                                            key={i}
                                            onClick={() => {
                                                if (showAnswer) return;
                                                setQuestions(prev => {
                                                    const c = [...prev];
                                                    c[currentQIndex].userAnswer = opt;
                                                    return c;
                                                });
                                            }}
                                            className={`group relative flex items-start gap-4 p-4 rounded-lg border transition-all duration-200 ${containerStyle}`}
                                        >
                                            <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 transition-colors ${circleStyle}`}>
                                                {showAnswer && isCorrect ? <Check size={14} /> : showAnswer && isWrong ? <X size={14} /> : letter}
                                            </div>
                                            <div className="flex-1 text-sm md:text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-6 rounded-lg border-l-4 text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500 text-emerald-900' : 'bg-slate-100 border-slate-400 text-slate-800'}`}>
                                    <h4 className="font-bold uppercase tracking-widest text-xs mb-2 opacity-70">
                                        {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                    </h4>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No additional clinical notes available." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Controls */}
                <div className="bg-white border-t border-slate-200 p-4 flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-20">
                    <button 
                        onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))}
                        disabled={currentQIndex === 0}
                        className="flex items-center gap-2 px-4 md:px-6 py-3 rounded-lg font-bold text-xs uppercase tracking-widest text-slate-600 hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                    >
                        <ChevronLeft size={16} /> Previous
                    </button>

                    <button 
                        onClick={() => {
                            if (currentQIndex === questions.length - 1) {
                                handleFinish();
                            } else {
                                setCurrentQIndex(prev => prev + 1);
                                setImgError(false);
                            }
                        }}
                        className="flex items-center gap-2 px-6 md:px-8 py-3 rounded-lg font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg hover:shadow-xl transition-all hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {currentQIndex === questions.length - 1 ? 'Submit' : 'Next'} 
                        {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}
                    </button>
                </div>
            </main>

            {/* Sidebar (Question Palette) - RESPONSIVE */}
            <aside className={`bg-white border-l border-slate-200 w-full md:w-80 flex-col shrink-0 transition-transform duration-300 absolute lg:relative inset-y-0 right-0 z-40 shadow-2xl lg:shadow-none ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full lg:hidden'} flex`}>
                <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                    <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 p-2 hover:bg-slate-200 rounded-full"><X size={20} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
                    <div className="grid grid-cols-5 gap-2">
                        {questions.map((q, i) => {
                            let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-400";
                            if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200";
                            else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-600";
                            else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";

                            return (
                                <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }}
                                    className={`aspect-square rounded flex items-center justify-center text-xs font-medium border transition-all relative group ${style}`}
                                >
                                    {i + 1}
                                    {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="p-5 border-t border-slate-200 bg-slate-50 space-y-3">
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-slate-800 rounded"></div> Current
                    </div>
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-slate-100 border border-slate-300 rounded"></div> Answered
                    </div>
                    <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <div className="w-3 h-3 bg-amber-50 border border-amber-400 rounded"></div> Flagged
                    </div>
                    <button onClick={exitQuiz} className="w-full mt-4 py-3 border border-rose-200 text-rose-600 rounded-lg text-xs font-bold uppercase tracking-widest hover:bg-rose-50 transition-colors">
                        Abort Session
                    </button>
                </div>
            </aside>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Score Card) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
        <div className="h-full bg-slate-100 flex items-center justify-center p-4 overflow-y-auto custom-scrollbar">
            <div className="bg-white max-w-2xl w-full rounded-[1.5rem] shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500">
                <div className="bg-slate-900 p-8 text-center text-white relative overflow-hidden">
                    <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 to-slate-900"></div>
                    <div className="relative z-10">
                        <h2 className="text-3xl font-display font-bold mb-2">Examination Report</h2>
                        <p className="text-slate-400 uppercase tracking-widest text-xs font-bold">Session ID: OT-{Date.now().toString().slice(-6)}</p>
                    </div>
                </div>

                <div className="p-8 md:p-12 space-y-8 text-center">
                    <div className="flex justify-center items-center gap-8">
                        <div className="text-center">
                            <span className="block text-5xl font-black text-slate-900 mb-1">{percentage}%</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Final Grade</span>
                        </div>
                        <div className="w-px h-16 bg-slate-200"></div>
                        <div className="text-center">
                            <span className="block text-5xl font-black text-slate-900 mb-1">{score}</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Correct Answers</span>
                        </div>
                    </div>

                    <div className={`p-4 rounded-xl border-l-4 text-left ${percentage >= 70 ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                        <h4 className={`font-bold text-sm uppercase tracking-wider mb-1 ${percentage >= 70 ? 'text-emerald-800' : 'text-rose-800'}`}>
                            {percentage >= 70 ? 'Satisfactory Performance' : 'Academic Warning'}
                        </h4>
                        <p className="text-sm opacity-80">
                            {percentage >= 70 
                                ? "You have demonstrated competency in the selected modules. Maintain study habits." 
                                : "Performance falls below the departmental threshold. Recommend reviewing flagged topics in the Atlas."}
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {hasMistakes ? (
                            <button onClick={retryIncorrectOnly} className="py-4 rounded-xl border-2 border-rose-100 bg-rose-50 text-rose-700 font-bold uppercase text-xs tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retry Mistakes
                            </button>
                        ) : (
                            <button onClick={retrySession} className="py-4 rounded-xl border-2 border-slate-100 bg-slate-50 text-slate-700 font-bold uppercase text-xs tracking-widest hover:bg-slate-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retake Exam
                            </button>
                        )}
                        <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="py-4 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-bold uppercase text-xs tracking-widest hover:border-slate-400 transition-all flex items-center justify-center gap-2">
                            <FileText size={16} /> Audit Answers
                        </button>
                    </div>

                    <button 
                        onClick={() => saveAndExit(false)}
                        className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold uppercase text-xs tracking-widest hover:bg-slate-800 transition-all"
                    >
                        Conclude Session
                    </button>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW (Audit Mode) ---
  if (view === 'review') {
    return (
        <div className="h-full bg-slate-50 flex flex-col">
            <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                <h2 className="font-bold text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                    <FileText size={16} /> Audit Log
                </h2>
                <button onClick={() => setView('results')} className="text-xs font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900">
                    Return to Score
                </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 space-y-6">
                <div className="max-w-4xl mx-auto space-y-4">
                    {questions.map((q, i) => (
                        <div key={i} className={`bg-white rounded-xl border p-6 md:p-8 shadow-sm ${q.userAnswer === q.correctOption ? 'border-emerald-200' : 'border-rose-200'}`}>
                            <div className="flex gap-4">
                                <span className={`text-sm font-mono font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>Q{i+1}</span>
                                <div className="space-y-4 flex-1">
                                    <h3 className="font-medium text-slate-900 leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />

                                    {q.data.questionImage && (
                                        <div className="p-2 border border-slate-100 bg-slate-50 rounded-lg w-fit">
                                            <img src={cleanImageUrl(q.data.questionImage)} className="max-h-40 rounded" alt="ref" />
                                        </div>
                                    )}

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                                        <div className={`p-3 rounded-lg border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}>
                                            <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Your Selection</span>
                                            <span className="font-bold" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} />
                                        </div>
                                        {q.userAnswer !== q.correctOption && (
                                            <div className="p-3 rounded-lg border bg-slate-50 border-slate-200 text-slate-900">
                                                <span className="block text-[10px] font-black uppercase opacity-50 mb-1">Correct Answer</span>
                                                <span className="font-bold" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

export default Quiz;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport }) => {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState(''); // New state for performance
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Sync with LocalStorage whenever mistakesVault changes
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the mistakes vault?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire mistakes history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-4 md:pt-6">
      {/* Search Header */}
      <div className={`rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-12 mb-6 md:mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-4 md:space-y-6">
          <div className="space-y-2">
            <h2 className="text-2xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Mistakes" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Vault" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder={showMistakesOnly ? "Search known errors..." : "Search anatomy terms, chapters or definitions..."}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-12 md:pl-14 pr-4 py-4 md:py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-white/50 outline-none focus:bg-white focus:text-slate-900 transition-all text-sm md:text-lg font-bold"
            />
            <Search className="absolute left-4 md:left-5 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-slate-500 transition-colors" size={20} />
          </div>

          <div className="flex flex-wrap gap-2 md:gap-3 items-center">
            {/* Filter Trigger Button */}
            <button 
              onClick={() => setIsFilterOpen(true)}
              className="flex items-center gap-2 px-4 md:px-6 py-2.5 md:py-3 bg-white text-slate-900 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest shadow-lg hover:bg-slate-100 transition-all"
            >
              <Filter size={14} /> Filters
              {(selectedCategories.length > 0 || showMistakesOnly || showWrittenOnly) && (
                 <span className="bg-slate-900 text-white px-2 py-0.5 rounded-md">Active</span>
              )}
            </button>

            {showMistakesOnly && mistakesVault.length > 0 && (
                <button 
                    onClick={clearAllMistakes}
                    className="flex items-center gap-2 px-4 py-3 rounded-xl bg-black/20 text-white hover:bg-white hover:text-rose-600 transition-all text-[10px] font-black uppercase"
                >
                    <Trash2 size={14} /> Wipe Vault
                </button>
            )}

            <div className="flex-1"></div>
            <button 
                onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors text-white"
                title="Sort A-Z"
            >
                <ArrowUpDown size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid - content-visibility: auto speeds up rendering */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakesVault.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}
              <div className="p-6 md:p-8 flex-1">
                <div className="flex items-center justify-between mb-3 md:mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 max-w-[70%] truncate">{q.category}</span>
                  {mistakesVault.includes(q.id) && (
                    <div className="flex items-center gap-2">
                        <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Mistake</span>
                        <button 
                            onClick={(e) => removeMistake(q.id, e)}
                            className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                            title="Resolve this mistake"
                        >
                            <Trash2 size={12} />
                        </button>
                    </div>
                  )}
                </div>
                <h3 className="text-lg md:text-xl font-black text-slate-800 leading-tight mb-3" dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, debouncedSearch) }} />
                <div className="relative pl-4 md:pl-6 border-l-4 border-slate-200">
                  <p className="text-sm md:text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "No mistakes recorded. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Vault Filters"
      />
    </div>
  );
};

export default QuestionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal, RefreshCw, Activity, Play, Settings,
  Stethoscope, FileText, Microscope, Clipboard
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'create' | 'repair'>('create');

  // Repair State
  const [isBatchRepairing, setIsBatchRepairing] = useState(false);
  const [batchStatus, setBatchStatus] = useState({ current: 0, total: 0 });

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  const missingOptionsCount = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4).length;
  }, [allQuestions]);

  const questionsToRepair = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4);
  }, [allQuestions]);

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
        setActiveTab('create');
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Clinical Analysis...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Accessing External Medical Database...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Extracting Anatomical Data...' : 'Synthesizing Clinical Vignette...');

      const prompt = isUrl 
        ? `TASK: Occupational Therapy & Anatomy Education.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE high-quality, board-level anatomy/physiology question relevant to Occupational Therapy.

           REQUIRED OUTPUT FORMAT (JSON):
           {
             "questionText": "Clinical vignette or direct anatomical question",
             "answerText": "Precise correct answer",
             "explanation": "Detailed physiological/anatomical explanation with clinical relevance to OT",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "System or Region (e.g., Upper Extremity, Nervous System)",
             "questionImage": "URL if available"
           }`
        : `TASK: Anatomical Question Synthesis for OT Students.
           INPUT: """${rawInput}"""
           INSTRUCTION: Create a professional anatomy/physiology question from this text. Focus on functional anatomy if possible. Include 3 plausible clinical distractors.

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Formatting Clinical Record...');

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Medical Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON found.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Finalizing Entry...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Error:", error);
      setIsAiLoading(false);
      alert("Analysis interrupted. Please verify the source content.");
    }
  };

  const repairQuestion = async (q: Question) => {
    setIsAiLoading(true);
    setLoadingStep(`Optimizing Record: ${q.id}...`);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `TASK: Generate Medical Distractors.
      QUESTION: "${q.questionText}"
      ANSWER: "${q.answerText}"
      INSTRUCTION: Provide 3 distinct, plausible, but incorrect anatomical/physiological options relevant to OT/Medical boards.

      RETURN JSON: { "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"] }`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["options"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
      onSave(repairedQ);
      setIsAiLoading(false);
      setLoadingStep('');
    } catch (e) {
      setIsAiLoading(false);
      alert("Repair failed.");
    }
  };

  const startBatchRepair = async () => {
    if (questionsToRepair.length === 0) return;
    if (!confirm(`Initialize batch repair for ${questionsToRepair.length} records?`)) return;

    setIsBatchRepairing(true);
    const totalCount = questionsToRepair.length;
    setBatchStatus({ current: 0, total: totalCount });

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let count = 0;
    for (const q of questionsToRepair) {
        count++;
        setBatchStatus({ current: count, total: totalCount });
        setLoadingStep(`Processing: ${count}/${totalCount}`);

        try {
            const prompt = `TASK: Generate Medical Distractors.
            QUESTION: "${q.questionText}"
            ANSWER: "${q.answerText}"
            RETURN JSON: { "options": ["Correct", "Wrong1", "Wrong2", "Wrong3"] }`;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            options: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["options"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");
            const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
            onSave(repairedQ);

            await new Promise(r => setTimeout(r, 500));
        } catch (e) {
            console.error("Batch failure", e);
        }
    }

    setIsBatchRepairing(false);
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-8 pb-32 animate-in fade-in duration-700">

      {!showPreview && (
        <div className="flex justify-center mb-6">
          <div className="glass-card p-1.5 rounded-2xl flex gap-1 shadow-sm border border-slate-200/60">
             <button 
              onClick={() => setActiveTab('create')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'create' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <Plus size={16} /> Add Clinical Entry
             </button>
             <button 
              onClick={() => setActiveTab('repair')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'repair' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <RefreshCw size={16} /> Database Repair 
               {missingOptionsCount > 0 && <span className="ml-1 px-1.5 py-0.5 bg-white text-rose-600 text-[9px] rounded-md font-black">{missingOptionsCount}</span>}
             </button>
          </div>
        </div>
      )}

      {/* REPAIR MODE */}
      {activeTab === 'repair' && !showPreview && (
        <div className="max-w-4xl mx-auto space-y-6">
           <div className="glass-card rounded-[2.5rem] p-6 md:p-12 space-y-8 relative overflow-hidden border border-white">
              <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="space-y-2">
                  <h2 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tight font-display">
                    Vault <span className="text-rose-500">Diagnostics</span>
                  </h2>
                  <p className="clinical-label text-slate-400">
                    Content Integrity System
                  </p>
                </div>

                {missingOptionsCount > 0 && (
                  <button 
                    onClick={startBatchRepair}
                    disabled={isBatchRepairing}
                    className="px-6 py-3 bg-rose-600 hover:bg-rose-500 text-white rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-rose-200 transition-all hover:-translate-y-1 disabled:opacity-50"
                  >
                    {isBatchRepairing ? <Loader2 size={16} className="animate-spin" /> : <Zap size={16} />}
                    Auto-Repair All
                  </button>
                )}
              </div>

              {missingOptionsCount === 0 ? (
                <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-3">
                   <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-2">
                      <CheckCircle2 size={24} />
                   </div>
                   <h3 className="text-emerald-900 font-bold text-lg">System Optimal</h3>
                   <p className="text-emerald-700/70 text-sm">All questions meet clinical format standards.</p>
                </div>
              ) : (
                <div className="space-y-4">
                   {isBatchRepairing && (
                      <div className="bg-rose-50 border border-rose-100 rounded-2xl p-6 space-y-3 animate-pulse">
                         <div className="flex justify-between items-center text-rose-700 font-black text-xs uppercase tracking-widest">
                            <span>Processing Records</span>
                            <span>{batchStatus.current} / {batchStatus.total}</span>
                         </div>
                         <div className="h-2 w-full bg-rose-100 rounded-full overflow-hidden">
                            <div 
                                className="h-full bg-rose-500 transition-all duration-500" 
                                style={{ width: `${(batchStatus.current / batchStatus.total) * 100}%` }}
                            ></div>
                         </div>
                      </div>
                   )}

                   <div className="grid gap-3">
                      {questionsToRepair.slice(0, 8).map((q) => (
                        <div key={q.id} className="bg-slate-50 border border-slate-100 rounded-2xl p-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-4 group hover:border-rose-200 transition-all">
                           <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 mb-1">
                                <AlertCircle size={12} className="text-rose-500" />
                                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{q.category}</span>
                              </div>
                              <h4 className="text-slate-800 font-bold text-sm truncate" dangerouslySetInnerHTML={{ __html: q.questionText }}></h4>
                           </div>
                           <button 
                             onClick={() => repairQuestion(q)}
                             disabled={isAiLoading || isBatchRepairing}
                             className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 hover:border-rose-300 text-slate-600 hover:text-rose-600 rounded-lg font-bold text-[10px] uppercase tracking-wider transition-all"
                           >
                             <Wand2 size={14} /> Fix
                           </button>
                        </div>
                      ))}
                   </div>
                </div>
              )}
           </div>
        </div>
      )}

      {/* CREATE MODE */}
      {activeTab === 'create' && !showPreview && (
        <div className="max-w-4xl mx-auto">
          <div className="glass-card rounded-[3rem] p-6 md:p-16 border border-white/50 shadow-xl relative overflow-hidden">
            <div className="relative z-10 space-y-6 md:space-y-10">

              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl flex items-center justify-center text-white shadow-lg border border-slate-700">
                  <Clipboard size={24} className="text-rose-400" />
                </div>
                <div>
                  <h2 className="text-2xl md:text-3xl font-black text-slate-900 font-display tracking-tight">Clinical <span className="text-rose-600">Architect</span></h2>
                  <p className="clinical-label text-slate-400">AI-Assisted Content Generation</p>
                </div>
              </div>

              <div className="relative group">
                <textarea
                  value={rawInput}
                  onChange={(e) => setRawInput(e.target.value)}
                  className="w-full h-40 md:h-64 p-4 md:p-8 bg-slate-50 text-slate-700 rounded-[2rem] border-2 border-slate-100 focus:border-rose-400 focus:bg-white outline-none font-medium text-base md:text-lg placeholder:text-slate-400 transition-all shadow-inner resize-none custom-scrollbar"
                  placeholder="Paste clinical notes, lecture text, or a URL to a medical article..."
                />
                <div className="absolute bottom-6 right-8 flex items-center gap-2 text-slate-400 font-black text-[10px] uppercase tracking-widest pointer-events-none hidden md:flex">
                  <FileText size={14} /> Input Source
                </div>
              </div>

              <div className="flex justify-end">
                <button 
                  onClick={processEverythingWithAI}
                  disabled={isAiLoading || !rawInput.trim()}
                  className="w-full md:w-auto px-10 py-5 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:hover:translate-y-0 flex items-center justify-center gap-3"
                >
                  {isAiLoading ? <Loader2 size={20} className="animate-spin" /> : <Stethoscope size={20} />}
                  <span>Generate Question</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* PREVIEW MODE */}
      {showPreview && (
        <div className="max-w-5xl mx-auto space-y-8">

          <div className="glass-card p-6 rounded-[2rem] flex flex-col md:flex-row justify-between items-center gap-6 shadow-md border border-white">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <button 
                onClick={resetSystem} 
                className="w-12 h-12 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600 hover:bg-rose-50 transition-colors flex items-center justify-center border border-slate-100"
              >
                <X size={20} />
              </button>
              <div>
                <h3 className="text-lg font-black text-slate-900 font-display">Draft Review</h3>
                <p className="clinical-label text-slate-400">Verify medical accuracy before saving</p>
              </div>
            </div>

            <div className="flex gap-3 w-full md:w-auto">
              <button 
                onClick={() => setIsManualEdit(!isManualEdit)} 
                className={`flex-1 md:flex-none px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest transition-all border-2 ${isManualEdit ? 'border-slate-900 bg-slate-900 text-white' : 'border-slate-200 text-slate-500 hover:border-slate-300'}`}
              >
                {isManualEdit ? 'View' : 'Edit'}
              </button>

              <button 
                onClick={handleGlobalPublish}
                className="flex-1 md:flex-none px-8 py-3 bg-emerald-600 text-white font-black text-xs uppercase tracking-widest rounded-xl shadow-lg shadow-emerald-100 hover:bg-emerald-500 hover:-translate-y-1 transition-all flex items-center justify-center gap-2"
              >
                <Save size={16} />
                Save
              </button>
            </div>
          </div>

          <div className="grid lg:grid-cols-12 gap-8">
            <div className="lg:col-span-8">
              {isManualEdit ? (
                <div className="glass-card rounded-[2.5rem] p-6 md:p-10 border border-slate-200 space-y-8">
                    <div className="space-y-2">
                      <label className="clinical-label text-slate-400 px-1">Classification</label>
                      <input 
                        type="text" 
                        value={formData.category} 
                        onChange={e => setFormData({...formData, category: e.target.value})}
                        className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-slate-800 outline-none focus:border-rose-400 transition-all"
                      />
                    </div>

                    <div className="space-y-2">
                      <label className="clinical-label text-slate-400 px-1">Question Stem</label>
                      <textarea 
                        value={formData.questionText} 
                        onChange={e => setFormData({...formData, questionText: e.target.value})}
                        className="w-full h-32 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-medium text-slate-700 outline-none focus:border-rose-400 custom-scrollbar transition-all"
                      />
                    </div>

                    <div className="space-y-4">
                      <label className="clinical-label text-slate-400 px-1">Options (Green = Correct)</label>
                      <div className="grid gap-3">
                        {formData.options.map((opt, i) => (
                          <div key={i} className="relative">
                            <div className={`absolute left-0 top-0 bottom-0 w-10 flex items-center justify-center rounded-l-xl border-y-2 border-l-2 ${opt === formData.answerText ? 'bg-emerald-100 border-emerald-200 text-emerald-700' : 'bg-slate-100 border-slate-200 text-slate-400'}`}>
                                <span className="font-black text-xs">{String.fromCharCode(65 + i)}</span>
                            </div>
                            <input 
                              type="text" 
                              value={opt} 
                              onChange={e => {
                                const newOpts = [...formData.options];
                                newOpts[i] = e.target.value;
                                setFormData({...formData, options: newOpts});
                              }}
                              className={`w-full py-3 pl-12 pr-4 rounded-xl font-medium text-sm outline-none border-2 transition-all ${opt === formData.answerText ? 'bg-emerald-50 border-emerald-200 text-emerald-900' : 'bg-white border-slate-200 text-slate-600 focus:border-rose-300'}`}
                            />
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="clinical-label text-slate-400 px-1">Explanation</label>
                      <textarea 
                        value={formData.explanation} 
                        onChange={e => setFormData({...formData, explanation: e.target.value})}
                        className="w-full h-32 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-medium text-slate-700 outline-none focus:border-rose-400 custom-scrollbar transition-all"
                      />
                    </div>
                </div>
              ) : (
                <div className="glass-card rounded-[2.5rem] overflow-hidden border border-slate-200 shadow-xl">
                  <div className="bg-slate-50/80 p-6 md:p-8 border-b border-slate-100">
                     <span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[10px] font-black text-slate-500 uppercase tracking-widest">
                        {formData.category}
                     </span>
                     <h3 className="mt-4 text-xl md:text-2xl font-black text-slate-900 leading-snug font-display" dangerouslySetInnerHTML={{ __html: formData.questionText }} />
                  </div>

                  <div className="p-6 md:p-8 space-y-6 bg-white">
                    <div className="grid gap-3">
                      {formData.options.map((opt, i) => (
                        <div key={i} className={`p-4 rounded-xl border-2 flex items-center gap-4 transition-all ${opt === formData.answerText ? 'border-emerald-500 bg-emerald-50 text-emerald-900' : 'border-slate-100 text-slate-500'}`}>
                          <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs ${opt === formData.answerText ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                            {String.fromCharCode(65 + i)}
                          </div>
                          <div className="font-bold text-sm" dangerouslySetInnerHTML={{ __html: opt }} />
                        </div>
                      ))}
                    </div>

                    <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100">
                       <div className="flex items-center gap-2 mb-3">
                          <Zap size={16} className="text-rose-500" />
                          <span className="clinical-label text-slate-400">Clinical Rationale</span>
                       </div>
                       <p className="text-sm font-medium text-slate-700 leading-relaxed" dangerouslySetInnerHTML={{ __html: formData.explanation }} />

                       {sources.length > 0 && (
                          <div className="mt-6 pt-4 border-t border-slate-200">
                            <div className="flex items-center gap-2 mb-2">
                                <Globe size={12} className="text-slate-400" />
                                <span className="clinical-label text-slate-400">References</span>
                            </div>
                            <div className="flex flex-wrap gap-2">
                              {sources.map((src, i) => (
                                <a key={i} href={src.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 px-3 py-1 bg-white border border-slate-200 rounded-full text-[10px] font-bold text-blue-600 hover:text-blue-700 hover:border-blue-300 transition-all">
                                  {src.title} <ExternalLink size={10} />
                                </a>
                              ))}
                            </div>
                          </div>
                       )}
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="lg:col-span-4 space-y-6">
              <div className="glass-card rounded-[2.5rem] p-8 border border-slate-200 sticky top-24">
                <div className="space-y-6">
                  <div className="flex items-center gap-2 border-b border-slate-100 pb-4">
                    <ImageIcon size={18} className="text-rose-500" />
                    <h4 className="clinical-label text-slate-900">Media Attachments</h4>
                  </div>

                  <div className="space-y-3">
                    <label className="clinical-label text-slate-400 block">Image URL</label>
                    <input 
                      type="url" 
                      value={formData.questionImage}
                      onChange={e => setFormData({...formData, questionImage: e.target.value})}
                      className="w-full p-3 rounded-xl bg-slate-50 border border-slate-200 text-xs font-medium text-slate-700 outline-none focus:border-rose-400 transition-all" 
                      placeholder="https://..."
                    />
                    {formData.questionImage && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-slate-200 bg-slate-50">
                            <img src={formData.questionImage} alt="Preview" className="w-full h-auto object-cover" />
                        </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Loading Overlay */}
      {(isAiLoading || isBatchRepairing) && (
        <div className="fixed inset-0 z-[150] bg-white/80 backdrop-blur-md flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
            <div className="glass-card p-8 rounded-[2rem] flex flex-col items-center shadow-2xl border border-white">
                <div className="relative mb-6">
                    <div className="w-16 h-16 border-4 border-rose-100 border-t-rose-500 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                        <Activity className="text-rose-500 animate-pulse" size={24} />
                    </div>
                </div>
                <h3 className="text-xl font-black text-slate-900 tracking-tight font-display text-center">{loadingStep}</h3>
                <p className="clinical-label text-slate-400 mt-2">Consulting Knowledge Base...</p>
            </div>
        </div>
      )}
    </div>
  );
};

export default QuestionBuilder;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, Check, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  BookOpen
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isShuffled, setIsShuffled] = useState(false);
  const [isReversed, setIsReversed] = useState(false); // Reverse Q/A

  // Filter States
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Mistakes Vault Logic
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Are you sure you want to permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Filtered Data
  const activeData = useMemo(() => {
    let filtered = data;

    // 1. Filter by Mistakes First (if active)
    if (showMistakesOnly) {
      filtered = filtered.filter(q => mistakesVault.includes(q.id));
    }

    // 2. Filter by Images
    if (showImagesOnly) {
      filtered = filtered.filter(q => q.questionImage || q.answerImage);
    }

    // 3. Filter by Category (works with Mistakes mode now)
    if (selectedCategories.length > 0) {
      filtered = filtered.filter(q => selectedCategories.includes(q.category));
    }

    // 4. Shuffle
    if (isShuffled) {
      return [...filtered].sort(() => Math.random() - 0.5);
    }

    return filtered;
  }, [data, showImagesOnly, selectedCategories, isShuffled, showMistakesOnly, mistakesVault]);

  // Reset index when data changes
  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [activeData.length, isShuffled, showMistakesOnly, selectedCategories, showImagesOnly]);

  // PERFORMANCE: Preload Next Card Images
  useEffect(() => {
    if (currentIndex < activeData.length - 1) {
        const nextCard = activeData[currentIndex + 1];
        if (nextCard.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextCard.questionImage);
        }
        if (nextCard.answerImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextCard.answerImage);
        }
    }
  }, [currentIndex, activeData]);

  const currentCard = activeData[currentIndex];

  // Determine content based on Reversal State
  const frontContent = isReversed ? {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  } : {
    label: 'Question',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  } : {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  };

  const handleNext = () => {
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) {
      cancel();
    } else {
      speak(text, currentCard.id + suffix);
    }
  };

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Cards`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => setShowMistakesOnly(!showMistakesOnly),
        colorTheme: 'amber'
    },
    {
        label: 'Visuals Only',
        subLabel: 'Diagrams',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => setShowImagesOnly(!showImagesOnly),
        colorTheme: 'indigo'
    }
  ];

  // Empty State
  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-in fade-in zoom-in-95 duration-500">
        <div className={`p-6 rounded-full ${showMistakesOnly ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-2">
            <h3 className="text-2xl font-black text-slate-800">
                {showMistakesOnly ? "Vault Cleared!" : "No Flashcards Found"}
            </h3>
            <p className="text-slate-500 font-medium max-w-xs mx-auto">
                {showMistakesOnly 
                    ? "Excellent work! You've resolved all recorded mistakes." 
                    : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-rose-600 transition-colors shadow-lg"
        >
          Reset All Filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Controls & Header */}
      <div className="flex justify-between items-center px-4 py-3 md:py-4 gap-2">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`p-2.5 md:p-3 rounded-xl border-2 transition-all flex items-center gap-2 ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter size={18} />
             {(selectedCategories.length > 0 || showImagesOnly || showMistakesOnly) && (
                 <span className="text-[10px] font-black bg-rose-600 text-white px-1.5 py-0.5 rounded-md">
                    {[selectedCategories.length > 0, showImagesOnly, showMistakesOnly].filter(Boolean).length}
                 </span>
             )}
           </button>

           <div className="flex flex-col justify-center px-1">
              <h2 className="text-[10px] md:text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-1">
                {showMistakesOnly ? <><AlertTriangle size={12} className="text-amber-500" /> Vault</> : <><BookOpen size={12} /> Deck</>}
              </h2>
              <span className="text-[10px] font-bold text-slate-300">
                {currentIndex + 1} / {activeData.length}
              </span>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`p-2.5 md:p-3 rounded-xl border-2 transition-all ${isReversed ? 'border-emerald-500 bg-emerald-50 text-emerald-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
             title="Reverse Card Sides"
           >
             <ArrowLeftRight size={18} />
           </button>
           <button 
             onClick={() => setIsShuffled(!isShuffled)}
             className={`p-2.5 md:p-3 rounded-xl border-2 transition-all ${isShuffled ? 'border-purple-500 bg-purple-50 text-purple-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Shuffle size={18} />
           </button>
        </div>
      </div>

      {/* Card Area */}
      <div className="flex-1 px-4 pb-4 md:pb-8 flex flex-col justify-center min-h-0 relative">
        <div 
          className="relative w-full h-full perspective-1000 group cursor-pointer"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front Face */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-xl shadow-slate-200/50 border-2 border-slate-100 p-6 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className={`text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] ${isReversed ? 'text-emerald-500' : 'text-slate-300'}`}>
                     {frontContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-rose-500 uppercase tracking-widest bg-rose-50 px-2 py-1 rounded-lg border border-rose-100">
                           <AlertTriangle size={10} /> Mistake
                       </div>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-4">
                 {frontContent.image && (
                   <div className="mb-6 md:mb-8 max-h-[30vh] md:max-h-[40vh] flex items-center justify-center shrink-0 w-full">
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <h2 className={`text-lg md:text-3xl font-black leading-snug md:leading-tight mb-4 break-words hyphens-auto w-full ${isReversed ? 'text-emerald-600' : 'text-slate-800'}`} dangerouslySetInnerHTML={{ __html: frontContent.text || '' }} />

                 {/* Explanation on Front if it's the Answer side (Reversed Mode) */}
                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-5 bg-emerald-50 rounded-2xl border border-emerald-100 text-left mt-2 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <span className="text-[9px] md:text-[10px] font-black text-emerald-600/60 uppercase tracking-widest block mb-1">Clinical Note</span>
                     <p className="text-xs md:text-sm font-medium text-emerald-800 leading-relaxed break-words" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-auto shrink-0 pt-2">
                 <div className="text-[9px] md:text-[10px] font-bold text-slate-300 uppercase tracking-widest truncate max-w-[70%] text-left">{currentCard.category}</div>
                 <div className="flex items-center gap-2 md:gap-3">
                    {/* Resolve Button */}
                    {showMistakesOnly && !frontContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-3 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-500 hover:text-white transition-all shadow-sm border border-emerald-100"
                            title="Mastered - Remove from Mistakes"
                        >
                            <CheckCircle2 size={20} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, frontContent.text || '', '-front')}
                        className="p-3 bg-slate-50 rounded-full text-slate-400 hover:bg-rose-50 hover:text-rose-600 transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-front') ? <VolumeX size={20} /> : <Volume2 size={20} />}
                    </button>
                 </div>
               </div>
            </div>

            {/* Back Face */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] shadow-xl p-6 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar text-white">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className={`text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] ${isReversed ? 'text-slate-400' : 'text-emerald-400'}`}>
                     {backContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-rose-300 uppercase tracking-widest bg-white/10 px-2 py-1 rounded-lg">
                           <AlertTriangle size={10} /> Mistake
                       </div>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-4">
                 {backContent.image && (
                   <div className="mb-6 md:mb-8 max-h-[30vh] md:max-h-[40vh] flex items-center justify-center shrink-0 w-full">
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg bg-white/5" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <p className={`text-lg md:text-3xl font-bold leading-snug md:leading-relaxed mb-4 break-words hyphens-auto w-full ${isReversed ? 'text-white' : 'text-emerald-400'}`} dangerouslySetInnerHTML={{ __html: backContent.text || '' }} />

                 {/* Explanation on Back if it's the Answer side (Normal Mode) */}
                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-5 bg-white/5 rounded-2xl border border-white/10 text-left mt-2 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <span className="text-[9px] md:text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Clinical Note</span>
                     <p className="text-xs md:text-sm font-medium text-slate-300 leading-relaxed break-words" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-auto shrink-0 pt-2">
                 <div className="text-[9px] md:text-[10px] font-bold text-slate-600 uppercase tracking-widest truncate max-w-[70%] text-left">{currentCard.category}</div>
                 <div className="flex items-center gap-2 md:gap-3">
                    {/* Resolve Button */}
                    {showMistakesOnly && !backContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-3 bg-emerald-500/20 text-emerald-400 rounded-full hover:bg-emerald-500 hover:text-white transition-all shadow-sm border border-emerald-500/30"
                            title="Mastered - Remove from Mistakes"
                        >
                            <CheckCircle2 size={20} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, backContent.text || '', '-back')}
                        className="p-3 bg-white/10 rounded-full text-slate-400 hover:bg-white/20 hover:text-white transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-back') ? <VolumeX size={20} /> : <Volume2 size={20} />}
                    </button>
                 </div>
               </div>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="px-6 pb-28 md:pb-12 pt-2 flex justify-center gap-4 md:gap-6">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="w-14 h-14 md:w-16 md:h-16 rounded-2xl bg-white border-2 border-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-30 hover:border-slate-300 hover:text-slate-600 transition-all shadow-sm active:scale-95"
        >
          <ArrowLeft size={22} strokeWidth={3} />
