        <button 
          onClick={() => setIsFlipped(!isFlipped)} 
          className="h-14 md:h-16 px-8 md:px-10 rounded-2xl bg-rose-600 text-white font-black uppercase tracking-widest text-[10px] md:text-xs hover:bg-rose-700 transition-all shadow-xl shadow-rose-200 flex items-center gap-2 md:gap-3 active:scale-95"
        >
          <RotateCcw size={16} /> Flip
