import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport }) => {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState(''); // New state for performance
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Sync with LocalStorage whenever mistakesVault changes
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the mistakes vault?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire mistakes history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Vault',
        subLabel: `${mistakesVault.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-4 md:pt-6">
      {/* Search Header */}
      <div className={`rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-12 mb-6 md:mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-4 md:space-y-6">
          <div className="space-y-2">
            <h2 className="text-2xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Mistakes" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Vault" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder={showMistakesOnly ? "Search known errors..." : "Search anatomy terms, chapters or definitions..."}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-12 md:pl-14 pr-4 py-4 md:py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-white/50 outline-none focus:bg-white focus:text-slate-900 transition-all text-sm md:text-lg font-bold"
            />
            <Search className="absolute left-4 md:left-5 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-slate-500 transition-colors" size={20} />
          </div>

          <div className="flex flex-wrap gap-2 md:gap-3 items-center">
            {/* Filter Trigger Button */}
            <button 
              onClick={() => setIsFilterOpen(true)}
              className="flex items-center gap-2 px-4 md:px-6 py-2.5 md:py-3 bg-white text-slate-900 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest shadow-lg hover:bg-slate-100 transition-all"
            >
              <Filter size={14} /> Filters
              {(selectedCategories.length > 0 || showMistakesOnly || showWrittenOnly) && (
                 <span className="bg-slate-900 text-white px-2 py-0.5 rounded-md">Active</span>
              )}
            </button>

            {showMistakesOnly && mistakesVault.length > 0 && (
                <button 
                    onClick={clearAllMistakes}
                    className="flex items-center gap-2 px-4 py-3 rounded-xl bg-black/20 text-white hover:bg-white hover:text-rose-600 transition-all text-[10px] font-black uppercase"
                >
                    <Trash2 size={14} /> Wipe Vault
                </button>
            )}

            <div className="flex-1"></div>
            <button 
                onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors text-white"
                title="Sort A-Z"
            >
                <ArrowUpDown size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid - content-visibility: auto speeds up rendering */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakesVault.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}
              <div className="p-6 md:p-8 flex-1">
                <div className="flex items-center justify-between mb-3 md:mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 max-w-[70%] truncate">{q.category}</span>
                  {mistakesVault.includes(q.id) && (
                    <div className="flex items-center gap-2">
                        <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Mistake</span>
                        <button 
                            onClick={(e) => removeMistake(q.id, e)}
                            className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                            title="Resolve this mistake"
                        >
                            <Trash2 size={12} />
                        </button>
                    </div>
                  )}
                </div>
                <h3 className="text-lg md:text-xl font-black text-slate-800 leading-tight mb-3" dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, debouncedSearch) }} />
                <div className="relative pl-4 md:pl-6 border-l-4 border-slate-200">
                  <p className="text-sm md:text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "No mistakes recorded. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Vault Filters"
      />
    </div>
  );
};

export default QuestionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal, RefreshCw, Activity, Play, Settings,
  Stethoscope, FileText, Microscope, Clipboard
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'create' | 'repair'>('create');

  // Repair State
  const [isBatchRepairing, setIsBatchRepairing] = useState(false);
  const [batchStatus, setBatchStatus] = useState({ current: 0, total: 0 });

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  const missingOptionsCount = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4).length;
  }, [allQuestions]);

  const questionsToRepair = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4);
  }, [allQuestions]);

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
        setActiveTab('create');
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Clinical Analysis...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Accessing External Medical Database...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Extracting Anatomical Data...' : 'Synthesizing Clinical Vignette...');

      const prompt = isUrl 
        ? `TASK: Occupational Therapy & Anatomy Education.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE high-quality, board-level anatomy/physiology question relevant to Occupational Therapy.

           REQUIRED OUTPUT FORMAT (JSON):
           {
             "questionText": "Clinical vignette or direct anatomical question",
             "answerText": "Precise correct answer",
             "explanation": "Detailed physiological/anatomical explanation with clinical relevance to OT",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "System or Region (e.g., Upper Extremity, Nervous System)",
             "questionImage": "URL if available"
           }`
        : `TASK: Anatomical Question Synthesis for OT Students.
           INPUT: """${rawInput}"""
           INSTRUCTION: Create a professional anatomy/physiology question from this text. Focus on functional anatomy if possible. Include 3 plausible clinical distractors.

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Formatting Clinical Record...');

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Medical Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON found.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Finalizing Entry...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Error:", error);
      setIsAiLoading(false);
      alert("Analysis interrupted. Please verify the source content.");
    }
  };

  const repairQuestion = async (q: Question) => {
    setIsAiLoading(true);
    setLoadingStep(`Optimizing Record: ${q.id}...`);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `TASK: Generate Medical Distractors.
      QUESTION: "${q.questionText}"
      ANSWER: "${q.answerText}"
      INSTRUCTION: Provide 3 distinct, plausible, but incorrect anatomical/physiological options relevant to OT/Medical boards.

      RETURN JSON: { "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"] }`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["options"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
      onSave(repairedQ);
      setIsAiLoading(false);
      setLoadingStep('');
    } catch (e) {
      setIsAiLoading(false);
      alert("Repair failed.");
    }
  };

  const startBatchRepair = async () => {
    if (questionsToRepair.length === 0) return;
    if (!confirm(`Initialize batch repair for ${questionsToRepair.length} records?`)) return;

    setIsBatchRepairing(true);
    const totalCount = questionsToRepair.length;
    setBatchStatus({ current: 0, total: totalCount });

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let count = 0;
    for (const q of questionsToRepair) {
        count++;
        setBatchStatus({ current: count, total: totalCount });
        setLoadingStep(`Processing: ${count}/${totalCount}`);

        try {
            const prompt = `TASK: Generate Medical Distractors.
            QUESTION: "${q.questionText}"
            ANSWER: "${q.answerText}"
            RETURN JSON: { "options": ["Correct", "Wrong1", "Wrong2", "Wrong3"] }`;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            options: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["options"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");
            const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
            onSave(repairedQ);

            await new Promise(r => setTimeout(r, 500));
        } catch (e) {
            console.error("Batch failure", e);
        }
    }

    setIsBatchRepairing(false);
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-8 pb-32 animate-in fade-in duration-700">

      {!showPreview && (
        <div className="flex justify-center mb-6">
          <div className="glass-card p-1.5 rounded-2xl flex gap-1 shadow-sm border border-slate-200/60">
             <button 
              onClick={() => setActiveTab('create')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'create' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <Plus size={16} /> Add Clinical Entry
             </button>
             <button 
              onClick={() => setActiveTab('repair')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'repair' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <RefreshCw size={16} /> Database Repair 
               {missingOptionsCount > 0 && <span className="ml-1 px-1.5 py-0.5 bg-white text-rose-600 text-[9px] rounded-md font-black">{missingOptionsCount}</span>}
             </button>
          </div>
        </div>
      )}

      {/* REPAIR MODE */}
      {activeTab === 'repair' && !showPreview && (
        <div className="max-w-4xl mx-auto space-y-6">
           <div className="glass-card rounded-[2.5rem] p-6 md:p-12 space-y-8 relative overflow-hidden border border-white">
              <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="space-y-2">
                  <h2 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tight font-display">
                    Vault <span className="text-rose-500">Diagnostics</span>
                  </h2>
                  <p className="clinical-label text-slate-400">
                    Content Integrity System
                  </p>
                </div>

                {missingOptionsCount > 0 && (
                  <button 
                    onClick={startBatchRepair}
                    disabled={isBatchRepairing}
                    className="px-6 py-3 bg-rose-600 hover:bg-rose-500 text-white rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-rose-200 transition-all hover:-translate-y-1 disabled:opacity-50"
                  >
                    {isBatchRepairing ? <Loader2 size={16} className="animate-spin" /> : <Zap size={16} />}
                    Auto-Repair All
                  </button>
                )}
              </div>

              {missingOptionsCount === 0 ? (
                <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-3">
                   <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-2">
                      <CheckCircle2 size={24} />
                   </div>
                   <h3 className="text-emerald-900 font-bold text-lg">System Optimal</h3>
                   <p className="text-emerald-700/70 text-sm">All questions meet clinical format standards.</p>
                </div>
              ) : (
                <div className="space-y-4">
                   {isBatchRepairing && (
                      <div className="bg-rose-50 border border-rose-100 rounded-2xl p-6 space-y-3 animate-pulse">
                         <div className="flex justify-between items-center text-rose-700 font-black text-xs uppercase tracking-widest">
                            <span>Processing Records</span>
                            <span>{batchStatus.current} / {batchStatus.total}</span>
                         </div>
                         <div className="h-2 w-full bg-rose-100 rounded-full overflow-hidden">
                            <div 
                                className="h-full bg-rose-500 transition-all duration-500" 
                                style={{ width: `${(batchStatus.current / batchStatus.total) * 100}%` }}
                            ></div>
                         </div>
                      </div>
                   )}

                   <div className="grid gap-3">
                      {questionsToRepair.slice(0, 8).map((q) => (
                        <div key={q.id} className="bg-slate-50 border border-slate-100 rounded-2xl p-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-4 group hover:border-rose-200 transition-all">
                           <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 mb-1">
                                <AlertCircle size={12} className="text-rose-500" />
                                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{q.category}</span>
                              </div>
                              <h4 className="text-slate-800 font-bold text-sm truncate" dangerouslySetInnerHTML={{ __html: q.questionText }}></h4>
                           </div>
                           <button 
                             onClick={() => repairQuestion(q)}
                             disabled={isAiLoading || isBatchRepairing}
                             className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 hover:border-rose-300 text-slate-600 hover:text-rose-600 rounded-lg font-bold text-[10px] uppercase tracking-wider transition-all"
                           >
                             <Wand2 size={14} /> Fix
                           </button>
                        </div>
                      ))}
                   </div>
                </div>
              )}
           </div>
        </div>
      )}

      {/* CREATE MODE */}
      {activeTab === 'create' && !showPreview && (
        <div className="max-w-4xl mx-auto">
          <div className="glass-card rounded-[3rem] p-6 md:p-16 border border-white/50 shadow-xl relative overflow-hidden">
            <div className="relative z-10 space-y-6 md:space-y-10">

              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl flex items-center justify-center text-white shadow-lg border border-slate-700">
                  <Clipboard size={24} className="text-rose-400" />
                </div>
                <div>
                  <h2 className="text-2xl md:text-3xl font-black text-slate-900 font-display tracking-tight">Clinical <span className="text-rose-600">Architect</span></h2>
                  <p className="clinical-label text-slate-400">AI-Assisted Content Generation</p>
                </div>
              </div>

              <div className="relative group">
                <textarea
                  value={rawInput}
                  onChange={(e) => setRawInput(e.target.value)}
                  className="w-full h-40 md:h-64 p-4 md:p-8 bg-slate-50 text-slate-700 rounded-[2rem] border-2 border-slate-100 focus:border-rose-400 focus:bg-white outline-none font-medium text-base md:text-lg placeholder:text-slate-400 transition-all shadow-inner resize-none custom-scrollbar"
                  placeholder="Paste clinical notes, lecture text, or a URL to a medical article..."
                />
                <div className="absolute bottom-6 right-8 flex items-center gap-2 text-slate-400 font-black text-[10px] uppercase tracking-widest pointer-events-none hidden md:flex">
                  <FileText size={14} /> Input Source
                </div>
              </div>

              <div className="flex justify-end">
                <button 
                  onClick={processEverythingWithAI}
                  disabled={isAiLoading || !rawInput.trim()}
                  className="w-full md:w-auto px-10 py-5 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:hover:translate-y-0 flex items-center justify-center gap-3"
                >
                  {isAiLoading ? <Loader2 size={20} className="animate-spin" /> : <Stethoscope size={20} />}
                  <span>Generate Question</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* PREVIEW MODE */}
      {showPreview && (
        <div className="max-w-5xl mx-auto space-y-8">

          <div className="glass-card p-6 rounded-[2rem] flex flex-col md:flex-row justify-between items-center gap-6 shadow-md border border-white">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <button 
                onClick={resetSystem} 
                className="w-12 h-12 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600 hover:bg-rose-50 transition-colors flex items-center justify-center border border-slate-100"
              >
                <X size={20} />
              </button>
              <div>
                <h3 className="text-lg font-black text-slate-900 font-display">Draft Review</h3>
                <p className="clinical-label text-slate-400">Verify medical accuracy before saving</p>
              </div>
            </div>

            <div className="flex gap-3 w-full md:w-auto">
              <button 
                onClick={() => setIsManualEdit(!isManualEdit)} 
                className={`flex-1 md:flex-none px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest transition-all border-2 ${isManualEdit ? 'border-slate-900 bg-slate-900 text-white' : 'border-slate-200 text-slate-500 hover:border-slate-300'}`}
              >
                {isManualEdit ? 'View' : 'Edit'}
              </button>

              <button 
                onClick={handleGlobalPublish}
                className="flex-1 md:flex-none px-8 py-3 bg-emerald-600 text-white font-black text-xs uppercase tracking-widest rounded-xl shadow-lg shadow-emerald-100 hover:bg-emerald-500 hover:-translate-y-1 transition-all flex items-center justify-center gap-2"
              >
                <Save size={16} />
                Save
              </button>
            </div>
          </div>

          <div className="grid lg:grid-cols-12 gap-8">
            <div className="lg:col-span-8">
              {isManualEdit ? (
                <div className="glass-card rounded-[2.5rem] p-6 md:p-10 border border-slate-200 space-y-8">
                    <div className="space-y-2">
                      <label className="clinical-label text-slate-400 px-1">Classification</label>
                      <input 
                        type="text" 
                        value={formData.category} 
                        onChange={e => setFormData({...formData, category: e.target.value})}
                        className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-slate-800 outline-none focus:border-rose-400 transition-all"
