import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Info, Search, Maximize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown, Layers, Scan
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=80&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [search, setSearch] = useState('');

  // Performance: Pagination for grid
  const [visibleLimit, setVisibleLimit] = useState(24);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  // Mistakes Vault Logic
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Are you sure you want to permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Extract all unique diagrams
  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    // 1. Group questions by image
    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    // 2. Filter by Mistakes
    if (showMistakesOnly) {
        items = items.filter(item => item.hasMistake);
    }

    // 3. Filter by Category
    if (selectedCategories.length > 0) {
        items = items.filter(item => selectedCategories.includes(item.category));
    }

    // 4. Filter by Search
    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  // Reset pagination when filters change
  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);

  // PERFORMANCE: Only render visible items
  const visibleItems = atlasItems.slice(0, visibleLimit);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50 relative">

      {/* 1. Header Section - Clean & Sticky */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-20 bg-slate-50/90 backdrop-blur-md border-b border-slate-200/60">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">

            {/* Search Bar */}
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors..." : "Search anatomical diagrams..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3.5 rounded-2xl bg-white border border-slate-200 text-slate-700 font-medium text-sm shadow-sm focus:shadow-md focus:border-rose-500/50 focus:ring-4 focus:ring-rose-500/10 outline-none transition-all placeholder:text-slate-400"
                />
            </div>

            {/* Filter Button */}
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[52px] px-4 md:px-6 rounded-2xl border transition-all flex items-center gap-2.5 font-bold text-xs uppercase tracking-wider shadow-sm hover:shadow-md active:scale-95 ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Mistakes Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-4 animate-in slide-in-from-top-2">
                <div className="bg-amber-50 border border-amber-100 rounded-xl px-4 py-3 flex items-center gap-3 text-amber-800">
                    <AlertTriangle size={18} className="text-amber-600 shrink-0" />
                    <div>
                        <span className="block text-xs font-black uppercase tracking-widest">Diagnostic Mode</span>
                        <span className="text-xs opacity-80">Showing {atlasItems.length} diagrams with unresolved errors.</span>
                    </div>
                </div>
            </div>
        )}
      </div>

      {/* 2. Grid Content */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar">
        <div className="max-w-7xl mx-auto pb-32">
            {atlasItems.length > 0 ? (
                <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 content-visibility-auto">
                    {visibleItems.map((item, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => setSelectedImage(item.url)}
                            className="group cursor-pointer bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:shadow-slate-200/50 hover:-translate-y-1 transition-all duration-300 flex flex-col overflow-hidden relative"
                        >
                            {/* Image Area */}
                            <div className="aspect-[4/3] bg-slate-100/50 relative overflow-hidden flex items-center justify-center p-6 border-b border-slate-50">
                                <div className="absolute inset-0 bg-grid-pattern opacity-50"></div>
                                <img 
                                    src={cleanImageUrl(item.url)} 
                                    className="max-w-full max-h-full object-contain relative z-10 transition-transform duration-700 group-hover:scale-110" 
                                    alt="Anatomy Diagram" 
                                    loading="lazy" 
                                />

                                {/* Hover Overlay */}
                                <div className="absolute inset-0 bg-slate-900/0 group-hover:bg-slate-900/10 transition-colors z-20 flex items-center justify-center">
                                    <div className="bg-white/90 backdrop-blur-sm text-slate-900 px-4 py-2 rounded-full font-bold text-xs shadow-lg opacity-0 translate-y-4 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 flex items-center gap-2">
                                        <Scan size={14} className="text-rose-500" /> View Map
                                    </div>
                                </div>

                                {item.hasMistake && (
