            <img 
                src={cleanImageUrl(activeEntry.url)} 
                className="max-w-full max-h-full object-contain rounded-lg shadow-2xl transition-transform duration-500" 
                alt="Active Diagram" 
            />
            {/* Zoom Hint */}
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-black/50 text-white/80 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 pointer-events-none border border-white/10">
                <Maximize2 size={12} /> Interactive View
            </div>
          </div>

          {/* Right: Data Points (Light Theme) */}
          <div className="flex-1 h-[55vh] md:h-full bg-white rounded-t-[2.5rem] md:rounded-none md:rounded-l-[2.5rem] overflow-hidden flex flex-col shadow-[-20px_0_40px_rgba(0,0,0,0.2)]">

            {/* Header */}
            <div className="p-6 md:p-8 border-b border-slate-100 bg-white sticky top-0 z-10">
              <div className="flex items-center gap-2 mb-2">
                  <span className="px-2 py-0.5 bg-rose-50 text-rose-600 rounded text-[9px] font-black uppercase tracking-widest border border-rose-100">
                    {activeEntry.category.split(':')[0]}
                  </span>
              </div>
              <h2 className="text-xl md:text-2xl font-display font-bold text-slate-900 leading-tight">
                Anatomical Structure Breakdown
              </h2>
            </div>

            {/* List */}
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 bg-slate-50/50 pb-safe">
              {activeEntry.related.map((point, pIdx) => {
                const isMistake = mistakesVault.includes(point.id);
                return (
                    <div key={pIdx} className={`relative p-5 md:p-6 rounded-2xl bg-white border transition-all duration-300 group hover:shadow-lg ${isMistake ? 'border-amber-200 ring-1 ring-amber-100' : 'border-slate-100 hover:border-slate-200'}`}>

                        {/* Status Badge */}
                        <div className="flex justify-between items-start mb-3">
                            <div className="flex items-center gap-2">
                                <span className={`flex items-center justify-center w-6 h-6 rounded-full text-[10px] font-bold border ${isMistake ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                    {pIdx + 1}
                                </span>
                                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Point of Interest</span>
                            </div>

                            {isMistake && (
                                <button 
                                    onClick={(e) => handleResolveMistake(point.id, e)}
                                    className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-lg text-[10px] font-black uppercase tracking-wider hover:bg-emerald-100 transition-colors"
                                >
                                    <CheckCircle2 size={12} /> Resolve
                                </button>
                            )}
                        </div>

                        {/* Content */}
                        <div className="space-y-3">
                            <p className="text-sm md:text-base font-bold text-slate-800 leading-relaxed" dangerouslySetInnerHTML={{ __html: point.questionText.replace(/In the diagram,?/i, '') }} />

                            <div className="relative pl-4 border-l-2 border-rose-200">
                                <p className="text-sm font-medium text-slate-600" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                            </div>
                        </div>

                    </div>
                );
              })}

              <div className="text-center py-8">
                  <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">End of Record</span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Filters Modal */}
      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Configuration"
      />
    </div>
  );
};

export default InteractiveAtlas;

