            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-black/60 text-white/90 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 border border-white/10 pointer-events-none">
