import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  BookOpen, Touchpad, Repeat
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=80&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  // PERSISTENCE: Load state from localStorage or default
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  // Filter States (Persisted)
  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Mistakes Vault
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE STATES: Effects to save progress on change
  useEffect(() => localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault)), [mistakesVault]);
  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakesVault.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    // If shuffled, we want a stable shuffle based on the seed or just simple for now
    // Ideally, shuffle should shuffle the array ONCE when enabled, not every render.
    // For simplicity in this fix, if shuffled is on, we use a memoized random sort, 
    // but to keep index valid we usually need a mapping. 
    // Simplified: Just filtering here. Real shuffle logic often requires a separate index map.
    // For now, we will apply filters. If shuffle is toggled, we reset index to 0 to avoid out of bounds.
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakesVault]);

  // Handle out of bounds if filters change
  useEffect(() => {
    if (currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  // Preload images
  useEffect(() => {
    if (currentIndex < activeData.length - 1) {
        const nextCard = activeData[currentIndex + 1];
        if (nextCard.questionImage) (new Image()).src = cleanImageUrl(nextCard.questionImage);
        if (nextCard.answerImage) (new Image()).src = cleanImageUrl(nextCard.answerImage);
    }
  }, [currentIndex, activeData]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const filterOptions: FilterOption[] = [
    { label: 'Mistakes Vault', subLabel: `${mistakesVault.length} Cards`, icon: AlertTriangle, isActive: showMistakesOnly, onClick: () => setShowMistakesOnly(!showMistakesOnly), colorTheme: 'amber' },
    { label: 'Visuals Only', subLabel: 'Diagrams', icon: ImageIcon, isActive: showImagesOnly, onClick: () => setShowImagesOnly(!showImagesOnly), colorTheme: 'indigo' }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-md border ${showMistakesOnly ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-400 border-slate-200'}`}>
           {showMistakesOnly ? <Trophy size={40} /> : <Layers size={40} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight">
                {showMistakesOnly ? "Vault Cleared" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all recorded mistakes." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Top Controls - Classic Bar */}
      <div className="flex justify-between items-center px-6 py-4">
        <div className="flex items-center gap-3">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`h-10 px-4 rounded-lg border transition-all flex items-center gap-2 text-xs font-bold uppercase tracking-wider ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'}`}
           >
             <Filter size={14} />
             <span>Filter</span>
             {(selectedCategories.length > 0 || showImagesOnly || showMistakesOnly) && (
                 <span className="w-5 h-5 flex items-center justify-center bg-rose-500 text-white rounded-full text-[9px] font-black ml-1">
                    {[selectedCategories.length > 0, showImagesOnly, showMistakesOnly].filter(Boolean).length}
                 </span>
             )}
           </button>

           <div className="hidden md:flex flex-col justify-center px-2">
              <h2 className="text-[10px] font-extrabold uppercase tracking-[0.2em] text-slate-400 flex items-center gap-1.5">
                {showMistakesOnly ? <><AlertTriangle size={12} className="text-amber-500" /> Mistakes Vault</> : <><BookOpen size={12} /> Study Deck</>}
              </h2>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`p-2.5 rounded-lg border transition-all hover:bg-slate-50 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-500'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight size={18} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`p-2.5 rounded-lg border transition-all hover:bg-slate-50 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-500'}`}
             title="Shuffle Deck"
           >
             <Shuffle size={18} />
           </button>
        </div>
      </div>

      {/* Card Container - Classic Solid Look */}
      <div className="flex-1 px-4 md:px-8 pb-4 md:pb-8 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full group cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front Face - Solid White Card */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-3xl border-2 border-slate-100 shadow-xl flex flex-col items-center text-center overflow-y-auto custom-scrollbar p-6 md:p-10">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className={`text-[10px] font-black uppercase tracking-[0.25em] ${isReversed ? 'text-emerald-600' : 'text-slate-400'}`}>
                     {frontContent.label}
                   </span>
                   <div className="flex items-center gap-2">
                       <span className="text-[10px] font-bold text-slate-400 font-mono tracking-widest">{currentIndex + 1} / {activeData.length}</span>
                       {showMistakesOnly && (
                           <div className="flex items-center gap-1 text-[9px] font-black text-rose-500 uppercase tracking-widest bg-rose-50 px-2 py-1 rounded border border-rose-100">
                               <AlertTriangle size={10} /> Mistake
                           </div>
                       )}
                   </div>
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-4 space-y-6 pointer-events-none">
                 {frontContent.image && (
                   <div className="max-h-[35vh] w-full flex items-center justify-center bg-slate-50 rounded-xl p-4 border border-slate-100">
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <h2 className={`text-xl md:text-3xl font-bold leading-relaxed text-slate-800 break-words w-full ${frontContent.text && frontContent.text.length > 100 ? 'md:text-2xl' : ''}`} dangerouslySetInnerHTML={{ __html: frontContent.text || '' }} />

                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 bg-slate-50 rounded-xl border border-slate-200 text-left mt-2 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Note</span>
                     <p className="text-sm font-medium text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-auto shrink-0 pt-4" onClick={e => e.stopPropagation()}>
                 <div className="text-[9px] font-bold text-slate-400 uppercase tracking-widest truncate max-w-[60%] text-left bg-slate-50 px-2 py-1 rounded-md border border-slate-100">
                    {currentCard.category}
                 </div>
                 <div className="flex items-center gap-3">
                    {showMistakesOnly && !frontContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-3 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-100 border border-emerald-200 transition-colors shadow-sm"
                            title="Mark Resolved"
                        >
                            <CheckCircle2 size={18} strokeWidth={2.5} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, frontContent.text || '', '-front')}
                        className="p-3 bg-slate-50 border border-slate-200 rounded-full text-slate-400 hover:text-slate-900 hover:border-slate-300 transition-all shadow-sm"
                    >
                        {isSpeaking && speakingId?.endsWith('-front') ? <VolumeX size={18} /> : <Volume2 size={18} />}
                    </button>
                 </div>
               </div>
            </div>

            {/* Back Face - Solid Darker/Different Card */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-50/80 rounded-3xl border-2 border-slate-200 shadow-xl flex flex-col items-center text-center overflow-y-auto custom-scrollbar p-6 md:p-10">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className={`text-[10px] font-black uppercase tracking-[0.25em] ${isReversed ? 'text-slate-400' : 'text-emerald-600'}`}>
                     {backContent.label}
                   </span>
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-4 space-y-6 pointer-events-none">
                 {backContent.image && (
                   <div className="max-h-[35vh] w-full flex items-center justify-center bg-white rounded-xl p-4 border border-slate-200 shadow-sm">
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <p className={`text-xl md:text-3xl font-bold leading-relaxed text-slate-900 break-words w-full ${backContent.text && backContent.text.length > 100 ? 'md:text-2xl' : ''}`} dangerouslySetInnerHTML={{ __html: backContent.text || '' }} />

                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 bg-white rounded-xl border border-slate-200 text-left mt-2 animate-in fade-in slide-in-from-bottom-2 shrink-0 shadow-sm">
                     <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Clinical Note</span>
                     <p className="text-sm font-medium text-slate-700 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="w-full flex justify-between items-end mt-auto shrink-0 pt-4" onClick={e => e.stopPropagation()}>
                 <div className="text-[9px] font-bold text-slate-400 uppercase tracking-widest truncate max-w-[60%] text-left bg-white px-2 py-1 rounded-md border border-slate-200">
                    {currentCard.category}
                 </div>
                 <div className="flex items-center gap-3">
                    {showMistakesOnly && !backContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-3 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-100 border border-emerald-200 transition-colors shadow-sm"
                            title="Mark Resolved"
                        >
                            <CheckCircle2 size={18} strokeWidth={2.5} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, backContent.text || '', '-back')}
                        className="p-3 bg-white border border-slate-200 rounded-full text-slate-400 hover:text-slate-900 hover:border-slate-300 transition-all shadow-sm"
                    >
                        {isSpeaking && speakingId?.endsWith('-back') ? <VolumeX size={18} /> : <Volume2 size={18} />}
                    </button>
                 </div>
               </div>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation - Bottom - Classic Buttons */}
      <div className="px-6 pb-28 md:pb-12 pt-4 flex justify-center gap-8 md:gap-12 items-center">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="h-14 px-8 rounded-2xl bg-white border-2 border-slate-200 flex items-center gap-3 text-slate-600 disabled:opacity-40 disabled:cursor-not-allowed hover:border-slate-300 hover:bg-slate-50 transition-all shadow-sm active:translate-y-0.5 font-bold uppercase text-xs tracking-wider"
        >
          <ArrowLeft size={18} /> Previous
        </button>

        {/* Visual Cue */}
        <div className="flex flex-col items-center gap-1 opacity-40">
            <Repeat size={20} className="text-slate-400" />
            <span className="text-[9px] font-bold uppercase tracking-widest text-slate-400">Flip</span>
        </div>

        <button 
          onClick={handleNext} 
          disabled={currentIndex === activeData.length - 1}
          className="h-14 px-10 rounded-2xl bg-slate-900 flex items-center gap-3 text-white disabled:opacity-40 disabled:cursor-not-allowed hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl active:translate-y-0.5 font-bold uppercase text-xs tracking-wider"
        >
          Next <ArrowRight size={18} />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

